const INSTRUMENTS = {
  // ═══════════════════════════════════════
  // I. CREDIT INSTRUMENTS
  // ═══════════════════════════════════════
  levloans: {
    category: "credit", name: "Leveraged Loans", subtitle: "TL, RCF — 1L/2L, covenant mechanics, SOFR pricing",
    color: T_.blue, icon: "\uD83D\uDCB5",
    whatItIs: "A leveraged loan is a senior secured debt instrument issued by a below-investment-grade company (typically rated B/BB), arranged by banks and syndicated to institutional investors (CLOs, mutual funds, hedge funds). The two main forms are Term Loans (TL — fully funded at close, amortizing or bullet) and Revolving Credit Facilities (RCF — undrawn commitment, draw/repay as needed). First lien (1L) loans have first-priority claim on collateral; second lien (2L) are subordinated. Leveraged loans are the core instrument of the PE-backed LBO market — when a sponsor buys a company, the debt package almost always includes a 1L TL + RCF.",
    structure: "Floating rate: SOFR + spread (typically 300-600 bps for 1L; 600-900+ bps for 2L). Floor: typically 0-100 bps SOFR floor. Maturity: 5-7 years (TL); 5 years (RCF). Amortization: 1% per year mandatory; bullet at maturity. Security: first-priority lien on substantially all assets (1L); second-priority on same collateral (2L). Covenants: 'covenant-lite' (cov-lite) is now standard (~90% of new issues) — only incurrence-based tests, no maintenance covenants. Cov-heavy loans have quarterly leverage or coverage tests (e.g., Net Debt/EBITDA < 6.0x). OID (Original Issue Discount): 98-99.5 typically — effectively an upfront fee. Prepayment: generally callable at par (soft call protection of 101 for 6-12 months on new issues). Credit agreement governs all terms — the key document.",
    whoUses: "Issuers: PE-backed companies (LBOs, dividend recaps, add-on acquisitions), leveraged corporates. Sponsors use leveraged loans because floating rate matches their variable cash flows and prepayment flexibility supports M&A execution. Investors: CLOs (~65-70% of the market — the dominant buyer), loan mutual funds, hedge funds, insurance companies, BDCs. CLO demand drives the leveraged loan market — when CLO issuance is strong, loan supply is absorbed easily and spreads tighten. Banks: arrange and syndicate but retain minimal exposure (originate-to-distribute model).",
    risks: "Credit risk: below-IG borrowers with 4-7x leverage; default rates historically 2-4% (through-cycle), spiking to 8-12% in recession. Recovery risk: 1L loans historically recover 60-80 cents in default; 2L recovers 20-40 cents. Liquidity risk: loans trade OTC with ~T+11 median settlement (improving from T+15-20 historically); less liquid than bonds, especially in stress. Covenant erosion: cov-lite terms give borrowers significant flexibility to incur additional debt, strip collateral, or move assets to unrestricted subsidiaries. SOFR basis risk: floating rate means interest expense rises with rates — borrower stress increases in high-rate environments. Subordination creep: aggressive sponsors can structurally subordinate existing 1L lenders through 'J. Crew' or 'Chewy' type moves.",
    howToAnalyze: "Leverage: Net Debt / EBITDA (total and through each tranche). Interest coverage: EBITDA / Cash Interest (should be >2.0x). Free cash flow: EBITDA - CapEx - Cash Interest - Taxes - Working Capital changes. Liquidity: RCF availability + cash on hand. EBITDA quality: add-backs, synergies, pro forma adjustments — always scrub the EBITDA. Sponsor: track record, equity cushion (equity as % of TEV), willingness to support. Comparable recovery: where would this loan recover in default? Look at asset coverage, enterprise value vs. debt quantum. Spread vs. risk: is the SOFR+ spread adequate compensation for leverage, cyclicality, and business quality? Red flags: declining EBITDA trends, excessive add-backs (>25% of EBITDA), aggressive liability management, insider selling, deteriorating liquidity.",
    capitalStructure: "Senior secured, first-priority lien — sits at the top of the capital structure. In a liquidation or restructuring, 1L term loans and RCFs are repaid first from collateral proceeds. 1L recovery: 60-80% historically. 2L sits below 1L but above unsecured bonds and equity — recovery: 20-40%. The RCF is pari passu with the 1L TL (same collateral, same priority) but may have a 'super-priority' position in some structures. In an LBO capital structure: RCF → 1L TL → 2L TL → Senior Unsecured Notes → Mezzanine → Preferred Equity → Common Equity.",
  },

  hybonds: {
    category: "credit", name: "High Yield Bonds", subtitle: "Fixed rate, indenture-driven, call structures, make-whole",
    color: T_.blue, icon: "\uD83D\uDCDC",
    whatItIs: "High yield (HY) bonds are fixed-rate, unsecured or secured debt instruments issued by below-investment-grade companies (rated BB+ or lower by S&P/Fitch, Ba1 or lower by Moody's). Unlike leveraged loans (floating rate, secured, bank-arranged), HY bonds are fixed rate, typically unsecured, and governed by an indenture (trust agreement between issuer and bondholders, with a trustee). HY bonds are the primary source of long-term, fixed-rate debt for leveraged companies. The market is ~$1.4 trillion outstanding in the US.",
    structure: "Fixed coupon: 5-10% typically (varies with credit quality and rates). Maturity: 5-10 years (8 years most common). Security: typically senior unsecured (sits below 1L loans). Some secured HY bonds exist ('secured notes'). Call structure: non-call period (typically 3-5 years) → callable at declining premiums. Example: 8-year bond, NC4 (non-call for 4 years), then callable at 104, 102, 100 in subsequent years. Make-whole: during the NC period, early redemption requires a 'make-whole' premium (present value of remaining coupons discounted at Treasury + 50 bps — expensive, rarely exercised). Equity clawback: allows issuer to redeem up to 35-40% of bonds at par + coupon using IPO/equity offering proceeds within the first 3 years. Change of control: put at 101 (bondholder can sell back at 101% of par if a change of control occurs). Indenture covenants: restricted payments (limits dividends/buybacks), debt incurrence (ratio-based), liens, asset sales, affiliate transactions.",
    whoUses: "Issuers: leveraged corporates, PE-backed companies (alongside leveraged loans), fallen angels (former IG issuers). HY bonds provide fixed-rate, long-duration funding — issuers lock in rates and push out maturities. Investors: HY mutual funds, ETFs (HYG, JNK), insurance companies, pension funds, hedge funds. The buyer base is different from loans — more retail/institutional fund flow driven. This makes HY bonds more liquid but also more volatile (fund flows drive prices). Underwriters: investment banks (Goldman, JPMorgan, BofA) underwrite and distribute.",
    risks: "Credit risk: default rates 2-4% (through-cycle), 8-12%+ in recession. Unsecured bonds recover less than secured loans — historical recovery: 30-50 cents (senior unsecured), 10-30 cents (subordinated). Interest rate risk: fixed-rate bonds lose value when rates rise (duration risk). A 7-year HY bond has ~5 years of duration — a 100 bps rate move changes price ~5%. Spread risk: HY spreads widen in risk-off environments (recession fears, market stress). 2022: HY spreads blew out 200-300 bps. Refinancing risk: if a company can't refinance maturing bonds, it faces default. 'Maturity wall' analysis is critical. Call risk: for investors, bonds may be called away when spreads tighten (reinvestment risk). Covenant leakage: modern HY indentures have significant flexibility — unrestricted subsidiary designations, J. Crew-style trapdoors.",
    howToAnalyze: "Yield to worst (YTW): the relevant yield metric — accounts for call features. Spread to worst: YTW minus interpolated Treasury rate. OAS (option-adjusted spread): strips out call optionality for cleaner comparison. Leverage: Net Debt / EBITDA. Coverage: EBITDA / Interest Expense. Recovery analysis: what's the bond worth in default? Enterprise value at distressed multiples minus senior secured claims. Relative value: spread vs. rating cohort, spread vs. industry peers, spread vs. secured loans from same issuer. Credit trend: is the company deleveraging or re-leveraging? Upgrade/downgrade trajectory. Maturity profile: when do bonds mature? Is there a refinancing cliff? Red flags: approaching maturity wall with wide spreads (can't refinance), declining EBITDA, aggressive restricted payments, auditor changes, management departures.",
    capitalStructure: "Typically senior unsecured — sits below secured bank debt (1L loans, RCF) and above subordinated notes, mezzanine, and equity. Priority waterfall in bankruptcy: DIP financing → Administrative claims → 1L Secured (RCF + TL) → 2L Secured → Senior Unsecured Bonds → Subordinated Bonds → Mezzanine → Preferred → Common Equity. Recovery expectations: senior unsecured HY bonds historically recover 30-50 cents. Secured HY bonds ('secured notes') sit alongside 1L loans and recover 50-70 cents.",
  },

  igbonds: {
    category: "credit", name: "Investment Grade Bonds", subtitle: "Spread to Treasury, duration, IG credit quality framework",
    color: T_.blue, icon: "\uD83C\uDFE6",
    whatItIs: "Investment grade (IG) bonds are fixed-rate debt instruments issued by companies rated BBB-/Baa3 or higher. These are the highest-quality corporate debt instruments — issued by blue-chip companies like Apple, Microsoft, JPMorgan, Johnson & Johnson. The IG market is massive (~$9 trillion outstanding in the US) and forms the core of institutional fixed income portfolios. IG bonds trade on spread to Treasury (e.g., 'Microsoft 10-year at T+60 bps') rather than on absolute yield. The market is driven by duration, credit quality, and relative value rather than default risk (IG defaults are rare — <0.5% annually).",
    structure: "Fixed coupon: 3-6% typically (varies with rates and credit quality). Maturity: 2-30 years (10-year most common benchmark). Some ultra-long 40-50 year bonds. Security: virtually always senior unsecured. Callable: most new IG bonds include a make-whole call (expensive — effectively non-callable economically). Some include par call 3-6 months before maturity. Covenants: very light — typically just a negative pledge (no securing future debt without equally securing these bonds) and a change of control put at 101. No financial maintenance covenants. Issued under a shelf registration (SEC Form S-3) for speed and flexibility — large IG issuers can tap the market in hours.",
    whoUses: "Issuers: investment-grade corporates (Apple, Microsoft, Amazon), banks, utilities, REITs, sovereign-related entities. Companies issue IG bonds to fund operations, M&A, buybacks, and capital expenditures at the lowest possible fixed rate. Investors: insurance companies (largest buyer — match long-dated liabilities), pension funds, sovereign wealth funds, central banks, IG bond funds (LQD, VCIT), individual investors. The buyer base is rate-sensitive and spread-sensitive. Banks hold IG bonds in investment portfolios. Underwriters: bulge-bracket investment banks run massive IG issuance desks.",
    risks: "Interest rate risk / duration: the dominant risk. IG bonds have 5-15 years of duration; a 100 bps rate increase on a 10-year duration bond = ~10% price decline. This is what destroyed portfolios in 2022. Spread risk: IG spreads widen in recession (typically 100-200 bps from trough to peak). BBB 'cliff risk': if a BBB issuer is downgraded to BB ('fallen angel'), forced selling by IG-only mandates causes sharp price declines. Inflation risk: fixed coupons lose real value in inflationary environments. Refinancing is less risky than HY but still relevant for BBB issuers with large maturity towers. Liquidity: generally good for benchmark issues but can deteriorate in stress for smaller issues or off-the-run bonds.",
    howToAnalyze: "Spread analysis: OAS (option-adjusted spread) vs. rating cohort, sector, and historical range. Z-spread for simpler comparison. Duration: modified duration and convexity for interest rate sensitivity. Credit quality: leverage (Debt/EBITDA), interest coverage (EBITDA/Interest), FCF generation, rating trajectory. For BBB: distance to downgrade trigger — how much EBITDA decline before ratings agencies act? Sector relative value: compare industrials vs. financials vs. utilities. New issue concession: new bonds typically price 5-15 bps wide of secondary — opportunity for active managers. Curve analysis: 2s/10s slope within issuer curve — is the term premium adequate? Total return: coupon + roll-down + spread change — IG investing is about carry and roll, not capital gains.",
    capitalStructure: "Senior unsecured — pari passu with other senior unsecured obligations. IG companies typically have simple capital structures: senior unsecured bonds + commercial paper + bank credit facility. Subordinated debt is rare in IG. Recovery in the unlikely event of default: 40-60 cents historically for senior unsecured IG. The key differentiator from HY: IG bonds are bought primarily for spread income and duration management, not for recovery analysis. Default is a tail risk, not a central scenario.",
  },

  privatecredit: {
    category: "credit", name: "Private Credit / Direct Lending", subtitle: "Unitranche, PIK, BDC structures, covenant-heavy",
    color: T_.blue, icon: "\uD83D\uDD12",
    whatItIs: "Private credit refers to non-bank lending to middle-market companies (typically $10-75M EBITDA) by specialized fund managers and BDCs (Business Development Companies). Unlike syndicated leveraged loans (broadly distributed), private credit is directly originated — one or a small club of lenders provides the entire debt package. The instrument is typically a 'unitranche' — a single-tranche loan that combines senior and subordinated risk into one facility, priced between where 1L and 2L would be independently. Private credit has grown from ~$500B to $1.7T+ AUM in a decade, driven by banks retreating from middle-market lending post-GFC regulation.",
    structure: "Unitranche: single tranche, first lien, SOFR + 500-700 bps (higher than broadly syndicated 1L). Often includes an AATL (Agreement Among Tranche Lenders) that splits the unitranche into a 'first-out' and 'last-out' tranche internally. PIK (Payment-in-Kind): interest is capitalized rather than paid in cash — common as a partial component (e.g., 8% cash + 3% PIK). Increases risk — debt grows over time. Maturity: 5-7 years, bullet. Covenants: maintenance covenants are standard in private credit (unlike cov-lite syndicated loans). Typical: leverage covenant (Net Debt/EBITDA tested quarterly, set 20-30% above closing leverage), minimum liquidity, fixed charge coverage. This is a key advantage for lenders — early warning and intervention rights. OID: 97-99 (higher than syndicated — compensates for illiquidity). Prepayment penalties: 2-1-0 (2% in year 1, 1% in year 2, par thereafter) or 3-2-1.",
    whoUses: "Issuers: PE-backed middle-market companies that need speed, certainty, and flexibility. Private credit closes faster than syndicated loans (2-4 weeks vs. 6-8 weeks) with guaranteed execution. Borrowers trade higher cost for certainty and a single lender relationship. Investors: direct lending funds (Ares, Apollo, Owl Rock/Blue Owl, Golub, HPS), BDCs (public: ARCC, BXSL, OBDC; private BDCs), insurance companies, pension funds. BDCs are publicly-traded vehicles regulated under the Investment Company Act — they must distribute 90%+ of income (similar to REITs) and provide retail access to private credit. LPs: pension funds, endowments, family offices allocate to private credit funds for yield premium over liquid credit.",
    risks: "Illiquidity: no secondary market — loans are held to maturity. Investors can't sell in stress. Valuation opacity: private credit is marked-to-model (not marked-to-market) — NAVs may not reflect true economic value, especially in stress. Managers have incentive to mark conservatively to avoid triggering covenant defaults. Concentration risk: smaller number of loans per fund means single-name defaults have outsized impact. Leverage on leverage: BDCs and funds use fund-level leverage (1.0-1.5x at the fund level) on top of borrower leverage (4-6x) — amplifies returns but also losses. Covenant lite creep: as competition intensifies, private credit terms are loosening — fewer covenants, more flexibility, convergence toward syndicated terms. Sponsor-lender conflict: PE sponsors may act in equity's interest (dividend recaps, asset stripping) at lenders' expense. PIK risk: PIK interest grows the debt balance — if the company can't ultimately pay, the 'interest' never converts to cash.",
    howToAnalyze: "All-in yield: SOFR + spread + OID amortization + fees — typically 10-13% for unitranche. Leverage: Net Debt / EBITDA (including all PIK accrual). Equity cushion: sponsor equity as % of total enterprise value — more equity = more protection for lenders (target: 35-50%+ equity cushion). Interest coverage: EBITDA / Total Interest (including PIK). Covenant headroom: how much EBITDA decline before covenant breach? (target: 20-30%+ headroom). Sponsor support: track record, fund vintage (early in fund life = more willing to support), commitment to equity. Portfolio metrics: weighted average yield, leverage, LTV, diversity score, non-accruals (% of portfolio not paying interest). BDC-specific: NAV per share trend, dividend coverage (NII / dividend), spillover income, realized/unrealized gains/losses. Red flags: rising non-accruals, dividend cuts, NAV erosion, excessive PIK as % of income, concentrated portfolios.",
    capitalStructure: "First lien, senior secured — top of the capital structure, equivalent to broadly syndicated 1L loans. Unitranche effectively replaces the 1L + 2L structure with a single tranche. Recovery in default: 60-80% historically (similar to 1L syndicated). The 'first-out / last-out' split within a unitranche creates internal subordination — first-out recovers closer to 80-90%, last-out closer to 40-60%. In a typical PE-backed middle-market capital structure: Unitranche (or 1L TL + 2L if separately tranched) → Mezzanine (if any) → Preferred Equity → Sponsor Common Equity. Private credit lenders aim to be the fulcrum security — the instrument that controls the restructuring outcome.",
  },

  mezz: {
    category: "credit", name: "Mezzanine Debt", subtitle: "Subordinated, equity kicker, PE-driven capital structures",
    color: T_.blue, icon: "\uD83C\uDFD7\uFE0F",
    whatItIs: "Mezzanine debt is subordinated, unsecured (or second-lien) financing that sits between senior secured debt and equity in the capital structure. It fills the 'gap' when a PE sponsor needs more leverage than senior lenders will provide but doesn't want to contribute more equity. Mezzanine typically carries a high cash coupon + PIK component + equity warrants, generating total returns of 15-20%+. It was the standard instrument in mid-2000s LBOs but has been partially displaced by unitranche and second-lien structures. Still relevant in situations requiring higher leverage than senior lenders allow.",
    structure: "Coupon: 10-14% total (often split: 8-10% cash pay + 2-4% PIK). Plus equity warrants: typically for 1-5% of the equity on a fully diluted basis (the 'equity kicker'). Maturity: 6-8 years (longer than senior debt — repaid last). Security: usually unsecured or second-lien. Structurally or contractually subordinated to senior debt. Covenants: may include financial maintenance covenants, but subordination agreement limits mezzanine lenders' enforcement rights — must wait for senior lenders to act first ('standstill' period of 90-180 days). Prepayment: non-call for 2-3 years, then callable with declining premiums. Intercreditor agreement: critical document governing the relationship between senior and mezzanine lenders — defines standstill, payment blockage, and enforcement waterfall.",
    whoUses: "Issuers: PE-backed companies in LBOs, growth financings, and recapitalizations where senior leverage capacity is maxed out. Mezzanine allows sponsors to reduce equity contribution (from 40-50% to 30-35% of total capitalization). Investors: dedicated mezzanine funds (Goldman Sachs Mezzanine Partners, Audax Mezzanine, Crescent Capital), insurance companies, BDCs. Mezzanine investors accept subordination risk in exchange for equity-like returns (15-20%+ IRR including warrants). Arrangers: typically placed privately by mezzanine-focused intermediaries or directly by funds.",
    risks: "Subordination: last debt tranche to be repaid in bankruptcy — recovery rates are low (10-30 cents historically). Structural subordination: if senior lenders have a lien on all assets, mezzanine is effectively unsecured against those assets. PIK accumulation: the debt balance grows over time if PIK compounds — increases credit risk at maturity. Covenant limitations: standstill agreements prevent mezzanine lenders from acting quickly in distress — by the time standstill expires, value may have deteriorated further. Execution risk on warrants: equity warrants may be worthless if the company underperforms or is restructured. Displacement: unitranche and second-lien loans have taken significant market share from traditional mezzanine — smaller addressable market. Illiquidity: no secondary market — held to maturity or restructured.",
    howToAnalyze: "Total return: cash coupon + PIK + warrant value = target 15-20% IRR. Leverage through mezzanine: Total Debt / EBITDA including mezzanine — often 5-7x total. Equity cushion below mezzanine: how much equity stands behind the mezzanine? (target: 30%+ of enterprise value). Attachment point: at what enterprise value decline does mezzanine impairment begin? (enterprise value / total debt through mezzanine). Senior leverage: how much senior debt sits ahead? More senior debt = less residual value for mezzanine in stress. Warrant coverage: % of equity represented by warrants — higher coverage improves total return potential. Sponsor quality: strong sponsors protect mezzanine investments through equity cures and additional support. Cash flow: can the company service total cash interest (senior + mezzanine cash pay) from free cash flow? Red flags: total leverage >7x, negative free cash flow after all cash interest, weak sponsor, cyclical business with mezzanine exposure.",
    capitalStructure: "Below senior secured debt, above preferred equity and common equity. Priority in bankruptcy: DIP → 1L Secured → 2L Secured → Senior Unsecured → Mezzanine / Subordinated → Preferred → Common Equity. Historical recovery: 10-30 cents. The 'fulcrum' dynamic: mezzanine is often the fulcrum security in highly leveraged capital structures — the tranche where the enterprise value 'breaks' and recovery drops below par. This means mezzanine holders often control the restructuring outcome and may convert to equity in a debt-for-equity swap.",
  },

  // ═══════════════════════════════════════
  // II. STRUCTURED CREDIT
  // ═══════════════════════════════════════
  clo: {
    category: "structured", name: "CLO (Collateralized Loan Obligation)", subtitle: "Tranched leverage on loan pools; AAA to equity",
    color: T_.purple, icon: "\uD83C\uDFE8",
    whatItIs: "A CLO is a securitization vehicle that buys a diversified pool of leveraged loans (typically 150-300 loans) and finances the purchase by issuing tranched securities — from AAA-rated senior notes down to unrated equity. The 'magic' of a CLO is financial engineering: by pooling diversified credit risk and tranching the cash flows, the CLO creates AAA-rated bonds from BB-rated loans. CLOs are the single largest buyer of leveraged loans (~65-70% of the market) — they ARE the leveraged loan market. Outstanding CLO AUM: ~$1 trillion in the US. A CLO is actively managed by a CLO manager (portfolio manager who buys/sells loans within the portfolio), unlike static ABS structures.",
    structure: "Typical capital structure: AAA (60-65% of deal, SOFR+110-135 bps), AA (10-12%, SOFR+200-250), A (6-8%, SOFR+250-300), BBB (4-6%, SOFR+350-450), BB (3-5%, SOFR+600-800), Equity (8-11%, unrated, residual cash flows — targets 12-18% IRR). Reinvestment period: 4-5 years (manager actively trades the loan portfolio). Non-call period: 1-2 years (equity cannot be called). Legal maturity: 12-13 years. Waterfall: interest and principal flow from top (AAA) to bottom (equity). Senior tranches are paid first; equity absorbs first losses. Key tests: overcollateralization (OC) test — par value of loans must exceed tranche par by a defined cushion. If OC test fails, cash flow is diverted from equity to delever senior tranches. Interest coverage (IC) test: similar concept for interest. CCC bucket: typically limited to 7.5% of portfolio at par (excess CCC holdings are haircut in OC test).",
    whoUses: "Investors: AAA — banks (largest buyers, for regulatory capital purposes), insurance companies, pension funds. Mezzanine (AA-BB) — insurance companies, credit funds, structured credit funds. Equity — CLO-focused hedge funds, credit opportunity funds, the CLO manager (required to hold 5% risk retention in EU). CLO managers: Blackstone (GSO/BXCM), Apollo, Ares, CSAM, PGIM, Carlyle, Palmer Square, Canyon Partners. Banks: arrange and warehouse the loans before CLO closing. The CLO market is critical to the functioning of the leveraged finance ecosystem — if CLO issuance stops, leveraged loan demand collapses.",
    risks: "Credit risk: if underlying loans default at rates exceeding the structural cushion, junior tranches suffer losses first. In 2008-2009: CLO equity was impaired but AAA tranches never suffered a principal loss (zero historical AAA CLO defaults). Correlation risk: if defaults cluster in specific industries or are correlated (recession), diversification benefits are reduced. Manager risk: CLO performance varies significantly by manager — loan selection, trading, and CCC management matter. Mark-to-market volatility: CLO tranches are traded — AAA can move 3-5 points in volatile markets. Equity can move 20-40 points. Structural risk: OC test failures force cash diversion away from equity — equity can receive zero cash flow for extended periods in stress. Reinvestment risk: during the reinvestment period, managers must deploy cash into a potentially deteriorating loan market.",
    howToAnalyze: "OC cushion: current OC test ratio vs. trigger — more cushion = more protection. A typical AAA OC test might trigger at 120%; current level might be 130%. That 10% cushion means the portfolio can lose ~10% of par value before AAA cash flows are affected. WARF (Weighted Average Rating Factor): portfolio credit quality metric. WAS (Weighted Average Spread): portfolio yield metric. Diversity score: Moody's metric measuring portfolio diversification. CCC exposure: % of portfolio rated CCC+ or below — critical for OC test. Manager track record: historical default rates, trading P&L, deal performance. Equity IRR: back-test returns (typically 12-18% for well-managed CLOs). Junior OC cushion: the BBB or BB OC test is the 'canary in the coal mine' — first to fail in stress. Price vs. NAV: for traded tranches, is the market price above or below the modeled break-even spread? Red flags: declining OC cushions, rising CCC bucket, high manager turnover, concentrated portfolio positions.",
    capitalStructure: "CLO tranches are structured obligations — they are not claims on a corporate entity but rather claims on the cash flows from a pool of leveraged loans. Priority: AAA is paid first (lowest risk, lowest return). Equity is paid last (highest risk, highest return). Subordination protects senior tranches: AAA has ~35-40% subordination (the portfolio would need to lose 35-40% of value before AAA takes a loss). BB has ~8-11% subordination. Equity has 0% subordination — absorbs first losses. Historical performance: AAA CLO tranches have NEVER defaulted. BB tranches have experienced losses in severe stress. Equity has been impaired in 2008-2009 but recovered for most vintages.",
  },

  cdomech: {
    category: "structured", name: "CDO / CLO Mechanics", subtitle: "Over-collateralization, waterfall math, reinvestment",
    color: T_.purple, icon: "\u2699\uFE0F",
    whatItIs: "The mechanics of collateralized debt obligations (CDOs/CLOs) center on the 'waterfall' — the rules governing how cash flows from the underlying asset pool are distributed to tranched investors. Understanding waterfall mechanics, overcollateralization (OC) tests, interest coverage (IC) tests, and reinvestment rules is essential for analyzing any structured credit product. The 2008 crisis was fundamentally a failure of CDO mechanics applied to correlated mortgage risk (CDO-squared, synthetic CDOs). Post-crisis CLOs (CLO 2.0/3.0) have stronger structural protections, better collateral (leveraged loans vs. subprime mortgages), and more transparent portfolios.",
    structure: "Interest waterfall (quarterly): (1) Trustee/admin fees, (2) Senior management fee, (3) AAA interest, (4) AA interest, (5) A interest, (6) OC/IC test compliance check — if tests fail, excess interest is diverted to pay down senior notes, (7) BBB interest, (8) BB interest, (9) Subordinate management fee (incentive fee), (10) Equity residual. Principal waterfall: similar priority but activated by amortization, defaults, or test failures. OC test mechanics: Par Value of Collateral / Par Value of Tranche + All Senior Tranches. Example: $500M collateral pool / $325M (AAA par) = 153.8% OC ratio. If trigger is 120%, there's 33.8% cushion. If loans default and par drops to $390M, OC = 120% — test is at the trigger, cash diversion begins. IC test: Interest Received / Interest Due on tranche + senior tranches. Ensures interest income is sufficient to service the debt.",
    whoUses: "CLO managers: must understand waterfall mechanics to optimize portfolio construction, manage CCC exposure, and avoid test failures. Structured credit analysts: at insurance companies, banks, and hedge funds — model cash flows under stress scenarios to determine tranche break-even default rates. Rating agencies: S&P, Moody's, Fitch rate CLO tranches based on expected loss under their stress scenarios. Risk managers: banks holding CLO positions model OC cushion deterioration under stress. Equity investors: model residual cash flows under various default/recovery scenarios to determine equity IRR.",
    risks: "Waterfall complexity: multiple interlocking tests and diversion mechanisms create non-linear payoff profiles — small changes in portfolio quality can trigger large changes in junior tranche cash flows. Correlation: waterfall math assumes a certain level of default correlation. If correlation is higher than modeled (systemic recession), losses accelerate beyond model predictions. This is what happened in 2008 with CDOs on subprime mortgages. Model risk: cash flow models are only as good as their default, recovery, and prepayment assumptions. Garbage in, garbage out. Manager moral hazard: managers may take actions that benefit equity (buying higher-yielding, riskier loans) at the expense of senior tranches. Risk retention rules partially mitigate this. Complexity premium: many investors don't fully understand waterfall mechanics — this creates both opportunity (for those who do) and systemic risk (for those who don't).",
    howToAnalyze: "Build a cash flow model: project quarterly interest income, default losses (default rate × (1 - recovery rate)), reinvestment proceeds, and waterfall distributions. Stress test: run scenarios with 3%, 5%, 8%, 12% annual default rates at various recovery rates (40%, 50%, 60%, 70%). Identify break-even: at what default rate does each tranche stop receiving full interest? At what rate does it suffer principal loss? OC cushion sensitivity: map OC cushion under stress to identify the 'cliff' — the point where test failures begin diverting cash. Equity IRR analysis: under base, stress, and severe stress scenarios, what is the equity IRR? Does the expected return compensate for downside risk? Vintage analysis: compare deal metrics across vintages — post-crisis (CLO 2.0+) structures have better protections than pre-crisis. Reinvestment period analysis: during reinvestment, the manager can trade into better credits or worse. Track manager reinvestment performance.",
    capitalStructure: "The waterfall creates a synthetic capital structure within the CLO. AAA = 'senior secured' equivalent (35-40% subordination). Mezzanine (AA through BB) = 'unsecured debt' equivalent (8-25% subordination). Equity = common equity (0% subordination, residual claim). The critical insight: each tranche's risk profile depends on the subordination below it and the quality of the collateral pool above it. A CLO AAA tranche with 38% subordination on a diversified loan pool is, statistically, safer than most single-name investment-grade bonds.",
  },

  abs: {
    category: "structured", name: "ABS (Asset-Backed Securities)", subtitle: "Consumer, auto, equipment — cash flow securitization",
    color: T_.purple, icon: "\uD83D\uDE97",
    whatItIs: "Asset-backed securities (ABS) are bonds backed by pools of consumer or commercial receivables — auto loans, credit card receivables, student loans, equipment leases, cell phone contracts, whole business franchises. The originator (bank, finance company, captive lender) sells receivables to a special purpose vehicle (SPV) which issues tranched securities. Unlike CLOs, ABS pools are typically static (no active management) and amortize as the underlying receivables pay down. ABS is a $1.5 trillion+ market that provides essential funding for consumer and equipment lending.",
    structure: "Tranching: similar to CLOs — senior (AAA/AA), mezzanine (A/BBB), and subordinate (BB/residual). Excess spread: the difference between the yield on the receivable pool and the coupon paid to ABS investors — first line of defense against losses. Credit enhancement: subordination + excess spread + reserve accounts + overcollateralization. Example auto ABS: $1B pool of auto loans yielding 7% → $900M AAA notes at 5%, $60M A notes at 6%, $40M subordinated. The $100M subordination + excess spread protects AAA. Revolving vs. amortizing: credit card ABS has a revolving period (pool replenishes); auto/equipment ABS amortize as loans pay down. Early amortization triggers: if portfolio performance deteriorates (delinquencies, charge-offs exceed thresholds), the revolving period ends and cash is trapped to pay down investors.",
    whoUses: "Issuers/originators: auto lenders (Ally, Capital One, GM Financial, Ford Motor Credit), credit card issuers (Chase, Citi, Amex), equipment lessors, fintech lenders (SoFi, Upstart). Securitization allows originators to: (1) fund more loans than their balance sheet can support, (2) achieve cheaper funding (AAA cost vs. corporate cost), (3) manage regulatory capital. Investors: money market funds (AAA short-dated ABS), insurance companies, banks, pension funds, PIMCO, BlackRock, Wellington. ABS is a core investment-grade fixed income allocation. Rating agencies: rate each tranche based on loss modeling and structural protections.",
    risks: "Credit risk: if the underlying borrowers default at rates exceeding credit enhancement, investors take losses. Auto ABS credit risk depends on FICO distribution, LTV, and loan term. Prepayment risk: borrowers can prepay loans, shortening the life of the ABS and returning principal sooner than expected (reinvestment risk). Extension risk: in stress, defaults reduce prepayments and extend the ABS life. Servicer risk: the servicer collects payments and manages delinquencies — servicer failure or poor servicing can impair recoveries. Correlation: recession drives simultaneous defaults across the pool, overwhelming credit enhancement designed for idiosyncratic defaults. Regulatory risk: consumer protection rules (CFPB) can change servicing practices or restrict origination standards.",
    howToAnalyze: "Collateral analysis: FICO score distribution, LTV (loan-to-value), geographic concentration, loan term, seasoning (age of loans). Loss curves: compare actual cumulative losses to initial projections and to prior vintages from the same issuer. Delinquency trends: 30/60/90-day delinquency rates — leading indicator of future losses. Excess spread: is excess spread sufficient to absorb current losses? If losses exceed excess spread, subordination is consumed. Credit enhancement: total credit enhancement as multiple of expected losses — 3-5x for AAA, 1.5-2x for BBB. Servicer quality: originator/servicer financial health, historical servicing performance, backup servicer. Prepayment speed: CPR (conditional prepayment rate) — faster prepayments return principal early but reduce interest income. Comparables: compare same-issuer shelf deals across vintages for performance benchmarking. Red flags: deteriorating delinquencies ahead of prior vintages, declining excess spread, servicer financial distress.",
    capitalStructure: "ABS tranches are structured claims on the cash flows of a static (or revolving) asset pool. There is no corporate obligor — the SPV is bankruptcy-remote from the originator (true sale opinion). Priority: AAA → AA → A → BBB → Subordinated/Residual. Credit enhancement for AAA is typically 15-30% (subordination + excess spread + reserves). ABS is not directly comparable to corporate bonds — the risk is pool credit risk, not single-name corporate risk. In bankruptcy of the originator, the ABS pool is ring-fenced (bankruptcy-remote) — ABS investors have a claim on the pool assets, not on the originator.",
  },

  cmbs: {
    category: "structured", name: "CMBS / RMBS", subtitle: "Commercial and residential mortgage-backed; real estate credit",
    color: T_.purple, icon: "\uD83C\uDFE0",
    whatItIs: "CMBS (Commercial Mortgage-Backed Securities) and RMBS (Residential Mortgage-Backed Securities) are bonds backed by pools of real estate mortgages. CMBS pools commercial property loans (office, retail, industrial, multifamily, hotel). RMBS pools residential home loans. Agency RMBS (Ginnie Mae, Fannie Mae, Freddie Mac) carries a government guarantee on principal — the largest bond market after Treasuries (~$9T outstanding). Non-agency RMBS/CMBS are purely private-label, without government support. CMBS/RMBS are critical instruments for real estate finance — they connect capital markets to property lending at massive scale.",
    structure: "CMBS conduit deal: 50-100 commercial mortgage loans pooled into tranches. Typical: AAA (70-75%), AA-BBB (15-20%), B/unrated first-loss (5-10%). Loan-level: fixed-rate, 10-year term, 25-30 year amortization schedule, balloon payment at maturity. LTV: 55-70% at origination. DSCR (Debt Service Coverage Ratio): 1.2-1.5x minimum. CMBS single-asset/single-borrower (SASB): one large loan on a trophy property — simpler analysis. Agency RMBS: pass-through structure — all principal and interest payments flow to investors, with agency guarantee on credit. Prepayment risk is the dominant risk. Non-agency RMBS: tranched like CMBS, with subordination protecting senior tranches. Higher yielding, credit risk on non-conforming or jumbo mortgages. Defeasance/yield maintenance: CMBS loans typically cannot be prepaid — borrower must either substitute Treasury collateral (defeasance) or pay yield maintenance premium.",
    whoUses: "CMBS issuers: investment banks (Goldman, JPMorgan, Deutsche Bank) originate and securitize commercial mortgages. Property owners/borrowers: use CMBS execution for non-recourse, fixed-rate financing at scale. RMBS: Fannie Mae, Freddie Mac, and Ginnie Mae guarantee and securitize conforming residential mortgages. Non-agency RMBS originated by banks and non-bank lenders. Investors: agency RMBS — the Fed (QE/QT), banks, insurance companies, pension funds, mortgage REITs. CMBS — insurance companies, CMBS-focused funds, banks, PIMCO, BlackRock. Special servicers: handle delinquent CMBS loans (Rialto, LNR, CWCapital, Midland).",
    risks: "CMBS credit risk: property cash flows decline (vacancy, rent cuts), borrower can't refinance at maturity (balloon risk). Post-COVID office CMBS is severely stressed — record ~11% delinquency rate (surpassing GFC peak) for office CMBS. CMBS maturity wall: large volume of CMBS maturing 2024-2027, many on office properties with impaired values. Special servicing rates are a key stress indicator. RMBS prepayment risk: when rates fall, homeowners refinance — investors receive principal early and must reinvest at lower rates. When rates rise, prepayments slow (extension risk). Non-agency RMBS credit risk: depends on borrower quality, LTV, and housing market conditions. Interest rate risk: significant duration in both CMBS and RMBS (3-10 years effective duration). Structural complexity: CMBS waterfall mechanics with controlling class rights, advancing provisions, and special servicer dynamics.",
    howToAnalyze: "CMBS: property-level analysis — NOI, DSCR (>1.25x healthy), LTV (<70% healthy), lease rollover schedule, tenant quality, market conditions. Delinquency and special servicing rates: what % of the pool is delinquent or in special servicing? Maturity schedule: when do underlying loans mature? Can they refinance in the current rate environment? Subordination: credit enhancement for each tranche. RMBS: prepayment analysis — CPR/PSA speed, duration, convexity. Credit (non-agency): FICO, LTV, DTI, geographic concentration, vintage analysis. OAS vs. comparables: is the spread adequate for the risk? Servicer quality: for CMBS, the special servicer's track record matters enormously — recovery rates vary by servicer. Red flags: rising delinquencies, office/retail exposure, high LTV at current values, concentrated geographic exposure, approaching maturity wall with wide spreads.",
    capitalStructure: "CMBS/RMBS tranches are structured claims on mortgage cash flows. Agency RMBS: government-guaranteed, no credit tranching — pure interest rate / prepayment product. Non-agency: tranched with subordination. AAA typically has 20-30% credit enhancement. First-loss pieces absorb initial losses. In CMBS, the 'controlling class' (lowest-rated outstanding tranche) has special rights — appoints the special servicer and can influence workout decisions. This creates conflicts between senior and junior holders. CMBS B-piece buyers (Rialto, KKR, Torchlight) specialize in first-loss CMBS investing — they conduct loan-by-loan due diligence and expect distressed returns (15-20%+).",
  },

  synthclo: {
    category: "structured", name: "Synthetic CLO / Bespoke Tranching", subtitle: "CDS-based exposure, unfunded structures",
    color: T_.purple, icon: "\uD83E\uDDEA",
    whatItIs: "A synthetic CLO uses credit default swaps (CDS) rather than cash loans to create exposure to a portfolio of credits. Instead of buying loans physically, the SPV sells protection on a reference portfolio via CDS — if a reference entity defaults, the SPV pays out. Investors in synthetic CLO tranches bear the credit risk without funding the full notional. 'Bespoke' tranches are custom-tailored for a single investor — the investor chooses the reference portfolio, attachment/detachment points, and maturity. Bespoke tranches grew pre-2008, were blamed for amplifying the crisis, and have resurged post-2020 as banks use them for regulatory capital relief (Significant Risk Transfer / SRT deals).",
    structure: "Reference portfolio: 50-100+ credits referenced by CDS. Tranching: attachment and detachment points define loss exposure. Example: 3-7% tranche absorbs losses between 3% and 7% of the portfolio notional. Below 3% = equity absorbs. Above 7% = senior tranches absorb. Unfunded vs. funded: unfunded tranches require no upfront investment — investor posts collateral and receives a premium (like selling insurance). Funded tranches: investor buys a credit-linked note (CLN) — principal at risk. SRT (Significant Risk Transfer): banks retain senior risk and transfer mezzanine/equity risk to investors via synthetic CLO — achieves regulatory capital relief under Basel III. The bank reduces risk-weighted assets; the investor earns attractive spread. Typical SRT: bank retains 0-100% of reference portfolio, transfers 3-10% mezzanine tranche to investor, retains senior risk.",
    whoUses: "Banks: use SRT/synthetic CLOs to manage regulatory capital. By transferring mezzanine risk, banks free up capital for new lending without selling loans. Major issuers: JPMorgan, Goldman, Barclays, BNP, Deutsche Bank. Investors: hedge funds (Magnetar, Saba, Man GLG), insurance companies, pension funds, credit opportunity funds. SRT investors earn attractive spreads (SOFR+400-1000 bps depending on tranche) for accepting defined credit risk. Structurers: investment bank desks create bespoke tranches tailored to investor preferences — custom attachment points, portfolio composition, maturity. Regulators: ECB and PRA have established frameworks for SRT; Fed/US regulation is evolving.",
    risks: "Correlation risk: synthetic tranches are highly sensitive to default correlation assumptions. If defaults are more correlated than modeled, mezzanine tranches suffer disproportionate losses. This was the central failure of CDOs in 2008 — correlation models massively underestimated systemic risk. Counterparty risk: unfunded structures depend on the protection buyer's (bank's) ability to pay premiums and the protection seller's (investor's) ability to post collateral. Model risk: pricing and risk management depend on correlation models, recovery assumptions, and default probability — all of which are uncertain. Liquidity: bespoke tranches have no secondary market — they are negotiated bilateral contracts. Complexity: the interaction between attachment points, correlation, and default timing creates non-linear, hard-to-intuit payoff profiles. Regulatory risk: rules around SRT capital relief may change, reducing bank demand.",
    howToAnalyze: "Expected loss: probability-weighted loss for the tranche under various default/correlation scenarios. Base correlation: market-implied correlation surface from CDX index tranches — used to price bespoke tranches. Spread analysis: tranche premium vs. expected loss — is the investor adequately compensated? Monte Carlo simulation: model thousands of default scenarios with varying correlation, timing, and recovery to generate loss distribution for each tranche. Attachment/detachment: thicker tranches (wider A/D spread) have more cushion; thinner tranches are more leveraged to credit events. Reference portfolio quality: average rating, industry concentration, single-name concentration, geographic exposure. SRT-specific: regulatory approval status, capital relief achieved, alignment of interest (bank retains first-loss and/or senior risk). Red flags: very thin tranches (e.g., 3-4% width), highly concentrated reference portfolio, opaque correlation assumptions, counterparty with weak credit.",
    capitalStructure: "Synthetic CLO tranches are unfunded or funded derivative exposures — they represent economic exposure to credit risk, not ownership of underlying assets. Priority follows the attachment/detachment waterfall: 0-3% equity tranche absorbs first 3% of portfolio losses. 3-7% mezzanine absorbs losses between 3% and 7%. 7-100% senior absorbs losses above 7% (rarely reached). Unlike cash CLOs, synthetic tranches are bilateral contracts between the bank and investor — there is no SPV holding physical assets. The investor's maximum loss is limited to the tranche notional (funded) or collateral posted (unfunded).",
  },

  // ═══════════════════════════════════════
  // III. DERIVATIVES & HEDGING
  // ═══════════════════════════════════════
  cds: {
    category: "derivatives", name: "CDS (Credit Default Swap)", subtitle: "Single-name and index; hedging, shorting credit, basis trades",
    color: T_.red, icon: "\uD83D\uDEE1\uFE0F",
    whatItIs: "A credit default swap is a bilateral derivative contract where the protection buyer pays a periodic premium (spread) to the protection seller in exchange for a contingent payment if a credit event occurs on a reference entity (default, bankruptcy, failure to pay, restructuring). CDS is essentially insurance on credit risk. Single-name CDS references one company. Index CDS (CDX, iTraxx) references a basket of credits. CDS is the primary tool for hedging, expressing views on, and trading credit risk without owning the underlying bonds or loans. CDS spreads are the most liquid and real-time indicator of credit risk in the market.",
    structure: "Premium leg: protection buyer pays quarterly (e.g., 300 bps/year = 75 bps/quarter on notional). Contingent leg: if a credit event occurs, protection seller pays (par - recovery) × notional. Physical settlement: buyer delivers defaulted bonds, seller pays par. Cash settlement: seller pays (par - auction recovery price) × notional. Standard terms: ISDA Master Agreement + Credit Derivatives Definitions. Maturities: 1, 3, 5, 7, 10 years (5-year is the benchmark). Standardized coupons: 100 bps (IG) or 500 bps (HY) with upfront exchange to adjust for market spread. Determinations Committee: ISDA DC decides whether a credit event has occurred and triggers auction. CDS Big Bang (2009): standardized fixed coupons, quarterly rolls, hardwired auction settlement.",
    whoUses: "Hedgers: loan portfolio managers, CLO managers, bond investors hedge credit exposure. Buy CDS to offset long credit positions without selling the underlying. Speculators: hedge funds express directional views on credit. Buy protection (short credit) if expecting deterioration; sell protection (long credit) if expecting improvement. Basis traders: exploit the CDS-bond basis (CDS spread vs. bond spread). Negative basis = CDS tighter than bond (buy bond, buy CDS protection — earn the basis). Banks: hedge loan portfolios and manage credit exposure. Synthetic CLO / SRT: CDS is the building block for synthetic structured credit. Market makers: dealer banks provide two-way CDS markets.",
    risks: "Counterparty risk: if the protection seller defaults, the buyer loses their hedge. Central clearing (via ICE Clear Credit) has reduced this for index CDS and liquid single-names. Basis risk: CDS and bond spreads can diverge significantly — 'the basis' is not stable. In 2008, CDS-bond basis blew out to 200+ bps. Liquidity risk: single-name CDS liquidity varies enormously — top 200 names are liquid, smaller names may have no market. Jump-to-default risk: CDS protection seller faces sudden, large payout on a credit event. Wrong-way risk: if the protection seller is correlated with the reference entity (e.g., buying CDS from a bank on another bank), the hedge fails when you need it most. Legal risk: disputes over whether a credit event has occurred (restructuring credit events are contentious).",
    howToAnalyze: "CDS spread: current spread vs. historical range, vs. rating cohort, vs. peers. A 5-year CDS at 500 bps implies ~8% annual probability of default (very rough approximation: spread / (1 - recovery)). CDS curve: term structure (1y, 3y, 5y, 10y) — steepness indicates market expectations. Inverted CDS curve (short-dated wider than long-dated) = market expects near-term distress. Basis: CDS spread minus Z-spread on comparable bond. Negative basis (CDS < bond) = potential opportunity. Positive basis (CDS > bond) = CDS market more bearish than bond market. Skew: compare CDS across the capital structure (senior vs. sub CDS). Recovery rate assumption: standard 40% for senior unsecured, 20% for subordinated. Implied default probability: use CDS spread and assumed recovery to back into market-implied PD. Technicals: net notional outstanding (DTCC data), recent trading volume, single-name vs. index positioning.",
    capitalStructure: "CDS is a derivative — it doesn't sit in the capital structure per se, but it references a specific obligation seniority. Senior CDS: references senior unsecured obligations (most common). Subordinated CDS: references subordinated debt (less common, wider spreads). Recovery rate assumption matters: senior CDS assumes ~40% recovery; subordinated assumes ~20%. In a credit event, the CDS auction determines the actual recovery rate — all CDS contracts on that name settle at the same auction price regardless of individual recovery rate assumptions.",
  },

  cdxindex: {
    category: "derivatives", name: "CDX IG / HY Indices", subtitle: "Standardized index CDS; market-wide credit sentiment",
    color: T_.red, icon: "\uD83D\uDCCA",
    whatItIs: "CDX indices are standardized portfolios of credit default swaps that serve as benchmarks for credit market health. CDX.NA.IG: 125 North American investment-grade names (the credit market equivalent of the S&P 500). CDX.NA.HY: 100 North American high-yield names. iTraxx Europe: 125 European IG names. These indices are the most liquid credit instruments in the world — they trade tighter bid/ask than any single-name CDS or bond. They roll every 6 months (March and September) with new constituents. CDX is the first thing credit traders look at every morning — it sets the tone for the entire credit market.",
    structure: "CDX.NA.IG: 125 equally-weighted IG names (0.8% each), 5-year maturity, fixed 100 bps coupon with upfront exchange. Trades in spread terms (e.g., 'CDX IG is 55 bps'). CDX.NA.HY: 100 equally-weighted HY names, 5-year, fixed 500 bps coupon. Trades in price terms (e.g., 'CDX HY is 108' — 108% of par). Series: new series every 6 months. 'On-the-run' is the current series; 'off-the-run' are older series. Constituent changes: removed for defaults, upgrades/downgrades across IG/HY boundary, mergers. Index tranches: CDX can be tranched — 0-3% equity, 3-7%, 7-15%, 15-100%. Tranche trading is the backbone of correlation trading and synthetic CLO pricing. Rolls: when a new series is issued, dealers offer 'roll' trades — sell off-the-run, buy on-the-run.",
    whoUses: "Macro hedgers: portfolio managers buy CDX IG protection to hedge broad IG credit exposure. If you own $1B of IG bonds, buying $1B notional CDX IG protection approximately hedges your spread risk. Relative value: trade CDX vs. single-name CDS (basis), trade CDX vs. CDX (IG vs. HY, or on-the-run vs. off-the-run), trade CDX vs. cash bonds. Directional: hedge funds use CDX for macro credit views — buy CDX HY protection if expecting recession, sell CDX IG protection if expecting spread tightening. Market makers: dealers trade CDX and hedge with single-name CDS positions. Correlation traders: trade CDX tranches to express views on correlation — equity tranche long-correlation, senior tranche short-correlation. ETF hedgers: credit ETF managers use CDX to manage inflows/outflows quickly while building/liquidating cash bond positions.",
    risks: "Basis risk: CDX may not move perfectly with your specific bond/loan portfolio — index composition may not match your holdings. Roll risk: transitioning from off-the-run to on-the-run series has a cost and may change your exposure (different constituents). Margin/collateral: CDX is cleared through ICE — requires initial margin and daily variation margin. In volatile markets, margin calls can force liquidation. Directional risk: CDX is a leveraged instrument — small capital outlay for large notional exposure. Mark-to-market losses can be significant. Crowded positioning: CDX is widely used for hedging — when many investors hedge simultaneously, CDX can overshoot (spreads widen beyond fundamentals) due to technical pressure.",
    howToAnalyze: "Current spread/price vs. historical range: CDX IG at 55 bps is near tights (complacent); at 150+ bps is stress (recession priced). CDX HY at 108 is tight; at 85-90 is distressed. Intrinsics: sum of constituent single-name CDS spreads should approximately equal the index level. If CDX trades wide of intrinsics, index is 'cheap' vs. single names (potential opportunity). Skew: dispersion of constituent spreads — wide dispersion means opportunities in relative value between names. Term structure: compare 3-year vs. 5-year CDX for curve steepness. Cross-market: CDX IG vs. iTraxx Europe for relative value across geographies. Correlation: implied correlation from tranche pricing — rising correlation means systemic risk expectations are increasing. Flow data: DTCC net notional and gross notional indicate positioning — large net protection buying = market is bearish.",
    capitalStructure: "CDX is a derivative instrument — no capital structure position. It references a portfolio of 125 (IG) or 100 (HY) senior unsecured obligations. CDX IG spread reflects the market-implied probability of default for investment-grade America. CDX HY spread/price reflects high-yield credit risk. CDX tranches create synthetic capital structure exposure: 0-3% equity tranche behaves like equity (first loss), 15-100% senior tranche behaves like AAA debt (last loss). The tranche market directly informs CLO pricing and synthetic structured credit economics.",
  },

  irs: {
    category: "derivatives", name: "Interest Rate Swaps", subtitle: "Fixed-to-float; duration hedging for bond portfolios",
    color: T_.red, icon: "\uD83D\uDD04",
    whatItIs: "An interest rate swap is a derivative contract where two parties exchange interest payments on a notional principal amount — one pays fixed, the other pays floating (typically SOFR). The most common is the 'plain vanilla' fixed-for-floating swap. No principal is exchanged — only the net interest differential is paid. IRS is the most widely traded derivative globally (~$500 trillion notional outstanding). It is the primary tool for managing interest rate exposure — converting floating-rate debt to fixed, hedging bond portfolio duration, and expressing rate views.",
    structure: "Fixed leg: one party pays a fixed rate (the 'swap rate') on the notional amount, quarterly or semi-annually. Floating leg: the other party pays SOFR (compounded in arrears) on the same notional. Net settlement: only the difference is paid each period. Example: $100M notional, 5-year swap, fixed rate 4.0%. If SOFR averages 5.0%, the fixed payer receives net 1.0% ($1M annualized) from the floating payer. Swap rate: determined by the market — reflects expectations for future SOFR rates plus a term premium. Swap spread: swap rate minus Treasury yield of the same maturity — indicates bank credit risk and supply/demand for swaps. DV01 (dollar value of a basis point): the change in swap value for a 1 bps change in rates — the key risk metric. Cleared through LCH or CME.",
    whoUses: "Corporates: convert floating-rate bank debt to fixed rate (buy a swap — pay fixed, receive floating). Or convert fixed-rate bonds to floating. Mortgage servicers: hedge prepayment risk and duration on mortgage servicing rights. Bond portfolio managers: manage portfolio duration by paying or receiving fixed. Insurance companies: match asset duration to liability duration using swaps. Banks: hedge interest rate risk in their loan and securities portfolios. Central banks: monitor swap rates as indicators of rate expectations and financial conditions. Relative value traders: trade swap spreads (swap rate vs. Treasury) and curve shape (2s10s, 5s30s).",
    risks: "Interest rate risk: if you're paying fixed and rates drop, the swap has negative mark-to-market. Duration of the swap determines sensitivity — a 10-year swap has ~8-9 years of DV01. Counterparty risk: mitigated by central clearing (LCH, CME) with daily margining. Uncleared swaps (bilateral) carry direct counterparty exposure. Basis risk: SOFR may not perfectly match the floating rate on your underlying exposure (if hedging SOFR+spread debt). Margin/collateral risk: large rate moves require posting significant variation margin — in 2022, rapid rate rises caused severe margin stress for UK pension funds (LDI crisis). Swap spread risk: swap spreads can move independently of rates — in 2008 and late 2023, Treasury-swap spread dynamics were highly unusual. Mark-to-market volatility: long-dated swaps can have significant MTM swings on daily rate moves.",
    howToAnalyze: "Swap rate vs. Treasury: the swap spread reflects credit and supply/demand factors — positive swap spread means swaps trade above Treasuries (normal). Negative swap spread (as seen in 30-year in 2023-2024) signals technical distortions. Forward curve: implied future SOFR rates from the swap curve — indicates where the market expects rates to go. Term premium: the excess return demanded for locking in rates longer-term. DV01: how much does the swap value change per basis point? A $100M 5-year swap has roughly $45K DV01. Hedge ratio: match the DV01 of your swap to the DV01 of the exposure you're hedging. Carry analysis: what is the current net payment on the swap? If receiving fixed above current SOFR, you earn positive carry. Curve shape: steepness of the swap curve implies rate expectations — inverted curve = market expects rate cuts.",
    capitalStructure: "Interest rate swaps are off-balance-sheet derivatives — they don't sit in the capital structure. However, they materially affect cash flows and risk profile. A company with floating-rate debt + a pay-fixed swap has economically converted to fixed-rate debt. In bankruptcy: derivatives are subject to the ISDA close-out netting framework and are typically net settled. Swap counterparties are not general unsecured creditors — they have netting and collateral rights. Central clearing further separates swap exposure from the corporate capital structure.",
  },

  trs: {
    category: "derivatives", name: "Total Return Swaps (TRS)", subtitle: "Synthetic exposure to loans/bonds without cash ownership",
    color: T_.red, icon: "\uD83D\uDD00",
    whatItIs: "A total return swap is a derivative contract where one party (the total return receiver) receives the total economic return (interest/coupons + price appreciation) of a reference asset, while paying a financing rate (SOFR + spread) to the other party (the total return payer, typically a bank). The receiver gets synthetic exposure to the asset without owning it — no cash outlay for the full purchase price, only collateral margin. TRS is widely used in leveraged loan markets for funds that want leveraged exposure to loans, for banks managing regulatory capital, and for accessing hard-to-source credits.",
    structure: "Total return leg: receiver gets all coupon payments + price appreciation (or pays price depreciation) on the reference asset. Financing leg: receiver pays SOFR + spread (typically 50-200 bps) on the notional amount. Margin: receiver posts initial margin (10-20% of notional for IG; 20-35% for HY/loans). Marks: the reference asset is marked to market periodically — margin calls if MTM moves against the receiver. Maturity: typically 1-3 years, with renewal options. Reset: periodic resets where PnL is settled and the swap is re-struck at current market price. The TRS payer (bank) usually owns the underlying asset and is economically lending it to the receiver — it's synthetic leverage. Alternatively, the payer may not own the asset and hedges separately.",
    whoUses: "Hedge funds: use TRS to gain leveraged exposure to leveraged loans or bonds without buying them outright. A fund with $100M equity can get $300-500M notional exposure via TRS — leveraged 3-5x. CLO warehouses: banks use TRS facilities to accumulate loans before CLO closing — the CLO manager selects loans, the bank funds them on TRS, then the loans are sold into the CLO. Credit funds: access specific bonds or loans they can't source in the cash market. Banks: manage loan portfolio risk — enter TRS as payer to economically transfer credit risk while retaining loan ownership. Regulatory capital arbitrage: TRS can be structured to achieve capital relief under certain accounting/regulatory treatments.",
    risks: "Leverage risk: TRS provides leveraged exposure — price declines are amplified. A 10% decline on 5x leveraged TRS = 50% loss on equity. Margin risk: if the reference asset declines in value, the receiver must post additional margin. Failure to post = forced unwind at potentially distressed prices. Counterparty risk: receiver depends on payer to honor the swap; payer depends on receiver to post margin and make payments. Financing cost risk: the SOFR + spread financing leg can become expensive if rates rise — eroding or eliminating the total return. Mark-to-market volatility: loans marked daily/weekly on TRS vs. potentially monthly in a fund — TRS forces real-time loss recognition. Rollover risk: at TRS maturity, the payer may not renew — forced to unwind or find new financing in potentially stressed markets.",
    howToAnalyze: "Excess return: total return of reference asset minus TRS financing cost. If the loan yields SOFR+400 and TRS financing is SOFR+150, the excess return is ~250 bps — before accounting for price movements and leverage. Leverage: notional exposure / equity posted. Higher leverage amplifies both returns and losses. Margin cushion: equity posted vs. maximum expected loss — is there sufficient margin to survive a price decline of X%? Liquidity of reference asset: can the TRS be unwound quickly? Liquid IG bonds = easy. Illiquid leveraged loans = harder. Counterparty quality: who is the TRS payer? A major bank is preferred. Rollover: what happens at maturity? Is renewal likely? What are the terms? Cost of carry: financing cost vs. asset yield — positive carry funds should earn money even without price appreciation. Red flags: excessive leverage (>5x), illiquid reference assets, short-dated TRS on long-dated assets (maturity mismatch), single counterparty.",
    capitalStructure: "TRS is an off-balance-sheet derivative — it provides synthetic economic exposure to a reference asset without ownership. The receiver has no claim on the reference asset itself — only a contractual claim against the TRS payer for the total return. In the receiver's bankruptcy, the TRS is subject to ISDA close-out netting. In the payer's bankruptcy, the receiver may lose their synthetic position and any unrealized gains. TRS exposure is economically equivalent to a financed position in the reference asset — same credit risk, amplified by leverage.",
  },

  swaptions: {
    category: "derivatives", name: "Options on Credit (Swaptions)", subtitle: "Volatility on rates; relevant in IG and structured markets",
    color: T_.red, icon: "\uD83D\uDCC8",
    whatItIs: "Swaptions are options on interest rate swaps — the right, but not the obligation, to enter into a swap at a predetermined rate (strike). A 'payer swaption' gives the right to pay fixed (profit if rates rise). A 'receiver swaption' gives the right to receive fixed (profit if rates fall). In credit markets, options-like instruments include CDS options (the right to buy/sell CDS protection at a strike spread), callable bond structures, and credit index options. Swaptions are the primary volatility instrument in rates markets — they price the market's expectation of future interest rate uncertainty.",
    structure: "Payer swaption: right to enter a pay-fixed swap. Example: '3-month into 5-year payer swaption at 4.0%' = in 3 months, the right to enter a 5-year swap paying 4.0% fixed. If swap rates are above 4.0% at expiry, the swaption is in-the-money. Receiver swaption: right to enter a receive-fixed swap. Used to hedge against rate declines. Straddles/strangles: combination of payer and receiver swaptions to trade volatility. CDS options: right to buy (put) or sell (call) CDS protection at a strike spread. Less liquid than rate swaptions but growing. Credit index options: options on CDX/iTraxx — available on exchange but less liquid than rate swaptions. Pricing: Black's model or SABR for swaptions. Key inputs: forward swap rate, strike, implied volatility (expressed in basis points or normal vol).",
    whoUses: "Mortgage hedgers: servicers and originators use swaptions to hedge pipeline risk and prepayment exposure — if rates drop, mortgages prepay and servicing values decline; receiver swaptions hedge this. Bond portfolio managers: use swaptions to express rate volatility views — buy straddles if expecting rate volatility to increase. Insurance companies: hedge guaranteed minimum rates in annuity products using receiver swaptions. Corporate treasurers: lock in future financing costs — buy payer swaptions to cap the rate on a future debt issuance. Relative value traders: trade implied vs. realized volatility, trade swaption skew, trade cross-currency swaption relative value. Structured product desks: embed swaption payoffs in structured notes for retail investors.",
    risks: "Premium risk: swaptions cost money (unlike swaps at inception which are zero cost). If rates don't move, the premium is lost. Time decay (theta): options lose value as expiration approaches — against the holder. Volatility risk (vega): swaption value is highly sensitive to implied volatility — a decline in vol can cause losses even if rates move favorably. Model risk: swaption pricing models (Black, SABR) rely on assumptions about rate distributions that may not hold in practice — negative rates, skew, and jumps aren't well-captured. Liquidity: OTC market — bid/ask spreads widen in stress, especially for off-market strikes and longer expiries. Gamma risk: near expiration, delta changes rapidly — hedging becomes expensive and volatile.",
    howToAnalyze: "Implied volatility: current implied vol vs. historical range. Is the market pricing too much or too little rate uncertainty? Compare implied vol (forward-looking) to realized vol (backward-looking). Vol surface: swaption vol varies by expiry (1m, 3m, 6m, 1y) and underlying tenor (2y, 5y, 10y, 30y). The 'vol cube' maps this surface. Skew: swaption vol at different strikes — skew indicates whether the market assigns higher probability to rate increases or decreases. Greeks: delta (rate sensitivity), gamma (convexity), vega (vol sensitivity), theta (time decay). Payoff analysis: model the PnL under various rate scenarios at expiry. Break-even: how much do rates need to move for the swaption to break even on premium paid? Carry and roll: how does the swaption's value change from time decay vs. mark-to-market from rate changes? Relative value: compare swaption vol to caps/floors vol, to equity vol (VIX), and to credit vol (CDX option vol) for cross-asset relationships.",
    capitalStructure: "Swaptions are off-balance-sheet derivatives. The buyer's maximum loss is the premium paid. The seller's potential loss is unlimited (for payer swaptions in a rising rate environment). Swaptions don't fit directly into a corporate capital structure — they are hedging or speculative instruments that modify the risk profile of existing positions. In the context of callable bonds: the issuer has effectively sold a receiver swaption to bondholders (the right to call = right to refinance at lower rates). Understanding embedded options in bonds requires swaption valuation skills.",
  },

  // ═══════════════════════════════════════
  // IV. EQUITY-LINKED & HYBRID
  // ═══════════════════════════════════════
  converts: {
    category: "hybrid", name: "Convertible Bonds", subtitle: "Debt with equity optionality; unique valuation framework",
    color: T_.amber, icon: "\uD83D\uDD00",
    whatItIs: "A convertible bond is a corporate bond that gives the holder the right to convert into a predetermined number of the issuer's common shares at a set conversion price. It's debt with an embedded equity call option. Converts offer investors downside protection (bond floor — the value of the bond ignoring conversion) with equity upside participation. They're typically issued by growth companies that want to raise debt at below-market coupons (because the conversion feature has value). The US convertible market is ~$300B+ outstanding.",
    structure: "Face value: typically $1,000 per bond. Coupon: 0-4% (lower than straight debt — investors accept lower coupon for equity optionality). Conversion price: fixed at issuance, typically 25-40% above the current stock price (the 'conversion premium'). Conversion ratio: face value / conversion price = number of shares per bond. Example: $1,000 face, conversion price $130, stock at $100 → conversion ratio = 7.69 shares, conversion premium = 30%. Maturity: 5-7 years typically. Call feature: issuer can force conversion after stock trades above 130-150% of conversion price for a sustained period ('soft call'). Put feature: holder can put the bond back to the issuer at par (usually at year 3 or 5) — downside protection. Make-whole: some converts include a make-whole on early conversion. Contingent conversion (CoCo): some require the stock to trade above a trigger before conversion is allowed.",
    whoUses: "Issuers: growth companies (tech, biotech, EV) that want cheap financing. Tesla, Airbnb, Palo Alto, Spotify have all issued converts. The coupon is 2-4% lower than straight debt because the investor gets equity upside. Pre-profit companies can issue converts when they can't access traditional HY markets. Investors: dedicated convertible arbitrage hedge funds (the largest buyer — buy the convert, short the stock to isolate the 'cheap' embedded option). Long-only convertible funds. Balanced/asset allocation funds that want equity exposure with downside protection. Income investors seeking yield with upside. Market makers: dealer desks trade converts and hedge delta.",
    risks: "Equity risk: if the stock declines significantly, the conversion option becomes worthless — the convert trades as a straight bond (the 'bond floor'), potentially at a loss if credit quality has deteriorated. Credit risk: converts are typically unsecured and subordinated in the capital structure — in bankruptcy, recovery may be low. Dilution: conversion increases shares outstanding, diluting existing shareholders. Interest rate risk: the bond floor is sensitive to rates — rising rates reduce the bond floor value. Call risk: if the issuer calls the bonds, investors may be forced to convert at a time that's suboptimal. Liquidity: smaller issue sizes and specialized investor base can mean wider bid/ask spreads. Complexity: the interaction between credit, equity, and volatility makes valuation non-trivial.",
    howToAnalyze: "Bond floor: value of the convert ignoring conversion — use comparable straight bond yield. If the convert as a straight bond would yield 7%, the bond floor is face value discounted at 7%. Conversion value (parity): stock price × conversion ratio. If parity > bond floor, the convert is 'in the money' and trades with equity-like sensitivity. Conversion premium: (convert price / parity - 1). High premium = more bond-like; low premium = more equity-like. Delta: sensitivity of convert price to stock price changes. ATM converts have ~50% delta. Deep out-of-the-money converts have ~10-20% delta (bond-like). Deep in-the-money have ~90%+ delta (equity-like). Implied volatility: back out the implied vol of the embedded option — compare to traded equity options. If convert implies lower vol, the option is 'cheap.' Yield-to-put/worst: the bond-like return if you hold to put/maturity and the stock hasn't risen. Credit assessment: analyze the issuer's credit quality independently — what's the bond floor worth? Convexity: converts have positive convexity — they participate in 60-80% of upside but only 30-50% of downside (when properly priced).",
    capitalStructure: "Convertible bonds are typically senior unsecured — they sit alongside regular unsecured bonds in priority. Some are subordinated. In bankruptcy: convert holders are treated as unsecured creditors for the face value of their claim. They cannot convert into equity in bankruptcy (equity is wiped out). Recovery: 20-40% historically for converts (similar to other unsecured debt). The conversion feature is a call option on the equity — it has value only as a going concern. Upon conversion, the converts disappear and shares are issued — the debt goes away and equity increases. This is dilutive to existing shareholders but deleveraging for the company.",
  },

  preferred: {
    category: "hybrid", name: "Preferred Equity", subtitle: "Between debt and equity; dividend mechanics",
    color: T_.amber, icon: "\uD83C\uDFAF",
    whatItIs: "Preferred stock sits between debt and common equity in the capital structure — it has a stated dividend rate (like a bond coupon) but dividends can be deferred without triggering default (unlike missed bond interest). Preferreds have priority over common equity in dividends and liquidation but are subordinate to all debt. For banks, preferred stock counts as Additional Tier 1 (AT1) capital — critical for regulatory compliance. For corporates, preferred dividends are often tax-advantaged for corporate holders (50-65% dividends received deduction). The preferred market is ~$500B+ outstanding, dominated by bank and utility issuers.",
    structure: "Par value: $25 (retail) or $1,000 (institutional). Dividend: fixed rate (e.g., 6.0% of par) or fixed-to-floating (fixed for 5-10 years, then SOFR + spread). Cumulative vs. non-cumulative: cumulative preferreds accumulate missed dividends — must be paid before common dividends resume. Non-cumulative (bank AT1) — missed dividends are gone forever. Callable: typically callable at par after 5 years. Perpetual: no maturity date (most preferreds); some have stated maturities (term preferred). Convertible preferred: converts into common stock at a set ratio (used in VC/PE). Liquidation preference: par value per share in liquidation — paid after all debt, before common equity. Bank AT1/CoCo: mandatory conversion or write-down trigger if CET1 falls below threshold (typically 5.125% or 7%).",
    whoUses: "Issuers: banks (AT1 capital for Basel III compliance — JPMorgan, BofA have $20-30B+ each in preferreds), utilities (regulated capital structures often include preferred), REITs, financial companies. Preferred is permanent capital with no maturity — attractive for issuers managing leverage ratios. Investors: retail income investors ($25 par preferreds — high individual investor ownership), insurance companies, preferred ETFs (PFF, PGX), corporate treasury (for the dividends received deduction — 50-65% of preferred dividends are tax-exempt for corporate holders). Bankers: arrange institutional preferred placements and manage shelf programs.",
    risks: "Interest rate sensitivity: preferreds have very long (often infinite) duration — extremely sensitive to rate changes. In 2022, preferred ETFs dropped 15-25% as rates rose. Dividend risk: non-cumulative preferreds (bank AT1) can skip dividends without consequence. In stress, regulators may restrict bank dividends. Credit/subordination: preferreds are deeply subordinated — in liquidation, they recover after ALL debt is repaid. Recovery rates: 0-20% historically in default. AT1 write-down: bank CoCo preferreds can be written down to zero if the bank's CET1 capital falls below the trigger. Credit Suisse AT1 holders received zero in the 2023 UBS merger (while equity got some recovery — unprecedented). Call risk: if rates decline, issuers call preferreds and refinance at lower rates — investors lose their high-coupon position. Extension risk: if rates rise, issuers don't call — investors are stuck with below-market coupons indefinitely.",
    howToAnalyze: "Current yield: annual dividend / current price. Yield-to-call: yield assuming called at first call date (relevant when trading above par). Yield-to-worst: the lower of yield-to-call and running yield. Stripped yield: adjusts for accumulated dividends. Credit quality: analyze issuer's overall capital structure — preferreds are deeply subordinated, so issuer health matters enormously. Rate sensitivity: modified duration (can be 10-20 years for perpetual preferreds). Spread to benchmark: preferred yield minus comparable Treasury or IG bond yield. Coverage ratio: issuer's earnings relative to total preferred dividends — how many times can the company cover its preferred dividend? Callable vs. non-callable: is the preferred trading above par (call risk) or below par (extension risk)? Relative value: compare preferred yield to baby bonds, perpetual bonds, and common stock dividend yield from the same issuer. Red flags: non-cumulative dividend from financially stressed issuer, AT1 from bank with weak capital, perpetual preferred trading far above par (call risk), preferred from company with deteriorating credit.",
    capitalStructure: "Preferred equity sits above common equity and below ALL debt in the priority waterfall: DIP → Secured Debt → Senior Unsecured Debt → Subordinated Debt → Preferred Equity → Common Equity. In liquidation: preferred holders receive their liquidation preference ($25 or $1,000 per share) after all creditors are paid but before common shareholders receive anything. In practice, there is rarely value left for preferred in bankruptcy — recovery is 0-20%. The 'hybrid' nature means preferred is treated as equity by rating agencies (no leverage impact) but as a fixed obligation economically. For banks: AT1 preferred counts as capital for regulatory purposes but can be written down or converted in severe stress (the 'gone concern' feature).",
  },

  warrants: {
    category: "hybrid", name: "Warrants", subtitle: "Equity kickers attached to debt; common in distressed",
    color: T_.amber, icon: "\uD83C\uDFAB",
    whatItIs: "Warrants are long-dated options issued by a company giving the holder the right to purchase shares at a predetermined price (strike/exercise price). Unlike exchange-traded options, warrants are issued by the company itself — exercise creates new shares (dilutive). In credit markets, warrants are commonly attached to high-yield debt or mezzanine as an 'equity kicker' — compensation for taking subordinated risk. In distressed situations, warrants are often distributed to creditors in restructurings as part of the recovery package (new equity + warrants on the reorganized company).",
    structure: "Exercise price: fixed at issuance (typically at or near current market price for distressed; at a premium for mezzanine). Expiration: 3-10 years (much longer than typical exchange-traded options). Coverage: expressed as % of fully diluted equity (e.g., 'warrants for 5% of the equity'). Exercise type: American (exercise any time) or European (exercise only at expiry). Black-Scholes: theoretically valued using option pricing models, but illiquidity, dilution, and long tenor complicate valuation. Penny warrants: in distressed restructurings, warrants may have a nominal exercise price ($0.01) — effectively free equity to compensate impaired creditors. Detachable vs. non-detachable: detachable warrants can be separated from the host debt and traded independently. Anti-dilution: standard protections against stock splits, dividends, and new issuances below exercise price.",
    whoUses: "Mezzanine lenders: receive warrants as part of the return package — the warrant's equity upside supplements the high cash coupon and PIK interest to target 15-20% total returns. Distressed creditors: in Chapter 11 reorganizations, old equity is typically cancelled and creditors receive new equity + warrants in the reorganized company. Example: creditors get 95% of new equity, old equity gets warrants for 5% (out-of-the-money). Venture debt / growth lending: Silicon Valley Bank, Hercules, Trinity Capital include warrants in growth lending packages. TARP: US government received warrants in banks during 2008 bailout (and profited when banks recovered). Sponsors: in some PE deals, management and sponsors receive warrant-like instruments aligned with equity performance.",
    risks: "Dilution: warrant exercise creates new shares — existing shareholders are diluted. This is the fundamental difference from exchange-traded options (which don't create new shares). Illiquidity: warrants issued in restructurings or attached to private debt typically have no trading market. Valuation uncertainty: long-dated warrants on companies emerging from distress are very hard to value — the company's equity value is uncertain, volatility is high, and there's no liquid market for price discovery. Out-of-the-money risk: if the company doesn't perform, warrants expire worthless. Time value erosion: as warrants approach expiration, time value decays (theta). Binary outcomes: in distressed situations, the reorganized company either performs (warrants become very valuable) or re-defaults (warrants are worthless).",
    howToAnalyze: "Intrinsic value: max(0, stock price - exercise price) × number of warrants. Time value: total warrant value minus intrinsic value — reflects the probability that the stock will exceed the exercise price before expiry. Black-Scholes: theoretical value using stock price, exercise price, time to expiry, volatility, risk-free rate. Adjust for dilution (diluted stock price = (shares × price + warrants × exercise) / (shares + warrants)). Leverage/gearing: warrants provide leveraged exposure to equity — small stock price changes produce larger % changes in warrant value. Coverage: what % of fully diluted equity do the warrants represent? Higher coverage = more dilution to existing shareholders but more value to warrant holders. Breakeven: stock price needed for the warrant to be worth the cost (or for restructuring warrants, the reorganized equity value needed to make the warrants valuable). Comparables: compare warrant implied volatility to traded options (if available) for relative value.",
    capitalStructure: "Warrants sit at the very bottom of the capital structure — below common equity in terms of priority (they are an option ON equity, not equity itself). In liquidation, warrants are worthless unless there is residual value after all creditors AND common equity are paid. In restructurings: warrants are typically given to the most junior impaired class (often old equity) as a 'tip' — the right to participate in recovery upside without any current claim. Warrants have zero recovery in liquidation. Their entire value is in the going-concern upside of the reorganized entity.",
  },

  pik: {
    category: "hybrid", name: "PIK Toggle Notes", subtitle: "Cash vs. PIK election; stress indicator in leveraged credits",
    color: T_.amber, icon: "\u26A0\uFE0F",
    whatItIs: "Payment-in-Kind (PIK) toggle notes give the issuer the option to pay interest either in cash or 'in kind' — by issuing additional notes in lieu of cash payment. The 'toggle' means the issuer can switch between cash and PIK payment each period. PIK increases the principal balance over time (debt grows instead of being serviced). PIK toggle notes were common in aggressive 2006-2007 LBOs and have resurged in 2023-2025 private credit. They are widely viewed as a stress signal — if a company toggles to PIK, it often means cash flow is insufficient to service the debt. PIK is particularly common in private credit unitranche facilities as a component of the coupon.",
    structure: "Coupon: typically 8-14% total, with toggle option. Example: 12% cash pay OR 13% PIK (higher rate to compensate for deferred cash). The 0.5-1.0% PIK premium penalizes the issuer for toggling. Toggle mechanism: issuer elects cash or PIK each interest period (typically quarterly or semi-annually). Some structures allow partial PIK (e.g., 8% cash + 4% PIK). Compounding: PIK interest is added to the principal — interest accrues on a growing balance. $100M at 13% PIK for 3 years becomes ~$140M+. Maturity: 5-8 years, bullet payment of the inflated principal. Covenants: PIK toggle notes typically have incurrence-based covenants (like HY bonds) rather than maintenance covenants. Some structures limit the number of periods PIK can be elected. Security: varies — can be senior secured, senior unsecured, or subordinated.",
    whoUses: "Issuers: PE-backed companies in leveraged capital structures where cash flow is tight relative to total debt service. The PIK toggle provides a safety valve — if EBITDA dips or working capital needs spike, the company can preserve cash by toggling to PIK. Highly cyclical businesses use PIK to manage through downturns. Sponsors: PE sponsors favor PIK toggle structures because they provide flexibility to manage portfolio company cash flows — avoid covenant defaults during temporary cash flow pressure. Investors: HY bond funds, private credit funds, CLOs (some can hold PIK bonds). PIK toggle bonds typically offer 100-200 bps more yield than comparable cash-pay bonds to compensate for the deferred payment risk. BDCs: significant holders of private credit with PIK components.",
    risks: "Debt accumulation: PIK means the debt balance grows — if the company can't ultimately pay the inflated principal, PIK was just delaying the inevitable default. PIK on PIK compounds the problem — the company owes progressively more. Cash flow signal: toggling to PIK is a warning sign — it often means the company can't generate sufficient free cash flow to service its obligations. Investors should view PIK toggling as a credit negative. Valuation opacity: PIK income is non-cash — funds that report PIK as income may overstate economic returns. A BDC earning 12% 'yield' where 4% is PIK is really earning 8% cash and hoping the PIK pays off later. Recovery risk: if the company ultimately defaults, the inflated PIK balance is a claim — but recovery on PIK notes is typically poor because the additional 'interest' was never cash that the company actually had. Complexity: the compounding math and toggle elections make PIK structures harder to analyze and model.",
    howToAnalyze: "Cash coverage: EBITDA / Cash Interest Only (excluding PIK). Can the company service the cash portion of its debt? If not, it will toggle to PIK — and the debt begins growing. Total debt trajectory: model the principal balance under full PIK, partial PIK, and full cash pay scenarios. How large does the debt become at maturity? PIK as % of total income: for fund investors, what percentage of reported income is PIK? Above 15-20% of portfolio income is a red flag. Toggle history: has the company toggled to PIK? How many periods? Persistent PIK toggling is a serious warning sign. Maturity analysis: can the company realistically refinance the inflated principal at maturity? Or is a restructuring likely? Sponsor behavior: is the PE sponsor continuing to support the company (equity cures, additional investment)? Or have they written off the equity? Compare cash vs. PIK yield: the PIK premium (extra yield for PIK) should be at least 50-100 bps — any less and the investor isn't adequately compensated for the deferral risk. Red flags: persistent PIK toggling, PIK balance exceeding 20%+ of original principal, negative free cash flow, sponsor disengagement, approaching maturity with wide spreads.",
    capitalStructure: "PIK toggle notes can sit at various levels — senior secured, senior unsecured, or subordinated — depending on the specific issuance. The key distinction: the PIK portion increases the claim over time. If a $100M note PIKs to $140M, the holder has a $140M claim in bankruptcy (though the additional $40M was never cash that existed in the business). In practice, PIK inflation of claims can create waterfall complications — more claims competing for the same enterprise value, reducing recovery rates for all creditors at that level. PIK notes at the senior secured level are more concerning than at the subordinated level — they inflate the senior claims and squeeze out junior creditors.",
  },

  // ═══════════════════════════════════════
  // V. DISTRESSED & SPECIAL SITUATIONS
  // ═══════════════════════════════════════
  dip: {
    category: "distressed", name: "DIP Financing", subtitle: "Senior-most claim; Chapter 11 mechanics",
    color: T_.green, icon: "\uD83C\uDFE5",
    whatItIs: "Debtor-in-Possession (DIP) financing is new money lent to a company after it files for Chapter 11 bankruptcy protection. DIP loans are granted super-priority status by the bankruptcy court — they are repaid before ALL pre-petition claims (even pre-petition secured debt). DIP financing keeps the company operating during bankruptcy, pays employees, maintains inventory, and funds the reorganization process. DIP providers have extraordinary protections: super-priority administrative claim, priming liens on collateral, tight covenants, milestones, and fees. DIP is the safest credit in a distressed capital structure — it's the senior-most claim that exists.",
    structure: "Super-priority: DIP has priority over all pre-petition claims under Section 364 of the Bankruptcy Code. Priming lien: DIP can be secured by a lien that 'primes' (sits ahead of) existing secured lenders' liens — requires court approval and adequate protection for primed lenders. Roll-up: existing pre-petition lenders often provide DIP financing and 'roll up' their pre-petition claims into the DIP — effectively elevating their priority. This is controversial and contested by other creditors. Size: ranges from $50M (small cases) to $10B+ (major cases). Pricing: SOFR + 600-1000+ bps (very expensive — reflects the distressed context and complexity). Fees: 2-5% upfront, commitment fees, ticking fees, exit fees. Covenants: extremely tight — milestones for the restructuring process, budget compliance, weekly/monthly reporting. Maturity: typically 12-18 months (duration of the Chapter 11 case).",
    whoUses: "DIP lenders: distressed hedge funds (Apollo, Oaktree, Elliott, Centerbridge), banks, existing pre-petition lenders. DIP lending is a specialized, high-return strategy — lenders earn above-market spreads with super-priority protection. Debtors: bankrupt companies that need liquidity to continue operating during Chapter 11. Without DIP, the company may be forced to liquidate under Chapter 7. Creditor committees: the Official Committee of Unsecured Creditors (UCC) scrutinizes DIP terms — particularly roll-ups and priming liens that may disadvantage unsecured creditors. Bankruptcy court: the judge must approve DIP financing under Section 364(c) or 364(d), finding it in the best interest of the estate.",
    risks: "Operational risk: the debtor may continue to deteriorate despite DIP financing — DIP lenders can lose money if the company's assets decline further. Priming challenges: existing secured creditors may object to priming — if the court denies priming, DIP may need to be unsecured or pari passu (less protective). Administration risk: complex bankruptcy cases take longer than expected — milestones may slip, requiring DIP amendments and additional fees. Conversion to Chapter 7: if reorganization fails and the case converts to liquidation, DIP still has super-priority — but liquidation proceeds may be insufficient. Competition: multiple parties may bid to provide DIP, compressing returns. Roll-up controversy: courts are increasingly scrutinizing roll-up DIPs that elevate pre-petition lender claims at the expense of other creditors (Serta, Envision litigation).",
    howToAnalyze: "Super-priority math: total DIP amount vs. liquidation value of the estate. Is there enough collateral/value to repay the DIP in full even in a worst-case liquidation? Adequate protection: are primed lenders adequately protected? (cushion between their claim and collateral value). Budget analysis: the DIP budget projects cash needs through emergence — is the budget realistic? Common areas of risk: working capital assumptions, professional fees, revenue trajectory. Milestones: are the restructuring milestones achievable? Key dates: filing date, exclusivity period, plan filing, confirmation hearing. Pricing: is the DIP fairly priced? Compare to other DIP facilities in similar cases. Roll-up analysis: how much pre-petition debt is being rolled into DIP? How does this affect other creditors' recoveries? Exit: how is the DIP repaid? Typically refinanced with exit financing upon emergence. Red flags: insufficient collateral coverage for DIP, unrealistic budget, contested DIP approval hearing, prior DIP defaults by the debtor.",
    capitalStructure: "DIP financing sits at the absolute top of the priority waterfall — above everything: DIP (super-priority administrative) → Administrative claims → Secured pre-petition claims → Unsecured pre-petition claims → Equity. DIP recovery expectation: 100% — DIP lenders expect to be repaid in full. If there isn't enough value to repay DIP, the company likely should be liquidating, not reorganizing. The 'priming' feature means DIP can sit ahead of pre-petition 1L secured claims on the same collateral — this is why existing secured lenders often provide the DIP themselves (defensive lending to protect their pre-petition position).",
  },

  exitfin: {
    category: "distressed", name: "Exit Financing", subtitle: "Post-reorganization capital structure design",
    color: T_.green, icon: "\uD83D\uDEAA",
    whatItIs: "Exit financing is the new debt package put in place when a company emerges from Chapter 11 bankruptcy. It replaces the DIP facility and funds the company's ongoing operations post-reorganization. The exit financing defines the reorganized company's capital structure — how much debt, at what cost, secured by what, with what covenants. Getting exit financing committed is a critical milestone in the Chapter 11 process — without it, the company can't emerge. Exit financing terms reflect the reorganized company's credit profile, which is typically improved (less debt, cleaner balance sheet) but still requires careful structuring.",
    structure: "Components: typically a revolving credit facility (RCF for liquidity) + term loan (funded debt). Some include HY bonds or private credit. Size: determined by the reorganized company's leverage capacity and cash needs. Leverage: emergence leverage is typically 2-4x Net Debt/EBITDA (significantly lower than pre-petition, reflecting the debt reduction in the plan of reorganization). Pricing: SOFR + 300-600 bps (tighter than DIP, reflecting reduced risk post-reorganization). Covenants: often maintenance covenants (leverage, coverage) — reorganized companies may accept tighter terms to demonstrate discipline. Maturity: 3-5 year term loan, 5-year RCF. Collateral: first-lien security on substantially all assets (standard). Commitment: exit financing commitments are obtained during the Chapter 11 process and are conditioned on plan confirmation and emergence — lenders commit to fund on the effective date.",
    whoUses: "Exit lenders: banks (JPMorgan, Goldman, BofA), direct lending funds, pre-petition creditors who convert their claims to exit debt. Banks provide exit RCFs; institutional investors take term loans. Pre-petition creditors: often provide exit financing as part of the restructuring agreement — they know the company and may receive favorable terms. Debtor: needs committed exit financing to confirm a plan of reorganization — it's required to demonstrate feasibility (the company can fund the plan and operate post-emergence). Sponsors: if a PE sponsor is involved in the reorganization (new or existing), they may arrange or co-invest in exit financing. Backstop parties: some plans include backstop commitments for exit financing (fee-based commitment to ensure financing is available).",
    risks: "Market risk: exit financing commitments are made months before emergence — credit markets may deteriorate, making terms worse or commitments unavailable. 'Market flex' provisions allow arrangers to adjust terms. Feasibility risk: if the reorganized company's projections are too optimistic, the exit debt may be unsustainable — leading to a re-filing ('Chapter 22'). About 15-20% of Chapter 11 companies re-file within 5 years. Execution risk: complex restructurings may face delays — exit financing commitments have expiration dates. Commitment uncertainty: exit financing may be subject to conditions (material adverse change, minimum liquidity) that create risk of the commitment being pulled. Leverage risk: while emergence leverage is typically conservative, the reorganized company may still face challenges — cyclical downturn, integration issues, or loss of key customers during bankruptcy.",
    howToAnalyze: "Emergence leverage: Net Debt / EBITDA at emergence — should be 2-4x for a sustainable reorganization. Higher leverage increases re-default risk. Cash flow adequacy: can the reorganized company service exit debt from operating cash flow? Model FCF under base and stress scenarios. Liquidity runway: RCF size + cash on hand — sufficient to cover working capital needs and seasonal fluctuations? Covenant headroom: if maintenance covenants, how much EBITDA decline before breach? (target: 25%+ cushion). Comparable analysis: what terms are similar companies getting in the current market? Is exit pricing fair relative to risk? Business plan: is the reorganization plan credible? Revenue and EBITDA projections, cost savings, capital expenditure requirements. Management: is the post-emergence management team capable? Turnaround experience? Commitment terms: read the commitment letter carefully — what are the conditions, the flex provisions, the expiration? Red flags: aggressive emergence projections, high exit leverage (>4x), tight liquidity, management turnover, key customer losses during bankruptcy.",
    capitalStructure: "Exit financing defines the reorganized company's capital structure. Typically: Exit RCF (1L secured, committed but undrawn) → Exit Term Loan (1L secured, funded) → possibly unsecured notes or second-lien → reorganized equity. All pre-petition debt is cancelled or converted in the plan of reorganization. The reorganized capital structure is designed to be sustainable — enough leverage to avoid immediate equity dilution to creditors but not so much that it risks re-default. Recovery analysis: exit debt lenders price their terms based on the reorganized company's enterprise value and leverage — they want to be well within the 'value break' to ensure full recovery in a future downside scenario.",
  },

  loantoown: {
    category: "distressed", name: "Loan-to-Own Strategies", subtitle: "Debt purchased at discount to convert to equity ownership",
    color: T_.green, icon: "\uD83C\uDFAF",
    whatItIs: "Loan-to-own is a distressed investing strategy where a creditor purchases a company's debt at a steep discount (30-70 cents on the dollar) with the intention of converting that debt to equity ownership through a restructuring. The investor accumulates a controlling position in the fulcrum security — the tranche where the enterprise value 'breaks' and recovery transitions from full to partial. By controlling the fulcrum, the investor controls the restructuring outcome: they propose the plan of reorganization, design the new capital structure, select management, and emerge as the majority equity holder. This is how many distressed investors become company operators.",
    structure: "Step 1 — Accumulate: buy the fulcrum security (typically senior unsecured bonds or 2L loans) at 30-70 cents. The position must be large enough to control the class vote (need 2/3 in amount, 1/2 in number for class acceptance under Section 1126). Step 2 — File or negotiate: either push for a Chapter 11 filing or negotiate an out-of-court restructuring (exchange offer). Step 3 — Propose plan: as the controlling creditor, propose a plan of reorganization where the fulcrum security converts to 100% (or majority) of the reorganized equity. Senior claims are paid in full (or close to it). Junior claims receive warrants or nothing. Step 4 — Emerge: the investor emerges as the controlling equity holder, having 'paid' the discounted debt purchase price for an equity position. If bought at 50 cents and the reorganized equity is worth 70+ cents, the investor profits. Restructuring support agreement (RSA): the investor and company sign an RSA pre-filing that locks in the deal terms — plan timeline, exit financing, governance.",
    whoUses: "Distressed hedge funds: Apollo, Oaktree, Elliott, Cerberus, Baupost, Centerbridge — these are the primary loan-to-own practitioners. They have dedicated teams for credit analysis, restructuring negotiation, and post-emergence operational management. Private equity: PE firms with distressed capabilities (Apollo, Cerberus) use loan-to-own as an alternative to traditional LBO — buy debt cheaply instead of buying equity at a premium. Active creditor groups: ad hoc groups of creditors organize to accumulate positions and negotiate collectively (often represented by restructuring advisors like Houlihan Lokey, PJT, Lazard). Legal advisors: Weil Gotshal, Kirkland & Ellis, Davis Polk, Milbank are the leading restructuring law firms.",
    risks: "Valuation risk: the entire strategy depends on the reorganized company being worth more than the debt purchase price — if enterprise value is lower than expected, the investor takes a loss. Fulcrum identification: getting the fulcrum wrong means you own the wrong tranche — either recovery is too high (bought too senior, limited upside) or too low (bought too junior, still impaired). Process risk: Chapter 11 is unpredictable — courts may approve competing plans, appoint examiners, or extend timelines. Litigation risk: other creditor classes may challenge the plan, object to valuation, or litigate intercompany issues — delaying emergence. Operational risk: post-emergence, the investor must actually run or oversee the company — this requires operational expertise that not all distressed investors have. Illiquidity: the investment is locked up through the bankruptcy process (6-18 months typically) with no ability to exit. Market timing: if credit markets deteriorate during the process, exit financing terms worsen and reorganized equity value may be lower.",
    howToAnalyze: "Enterprise value: the central question — what is the company worth? Estimate reorganized TEV using: EBITDA × appropriate multiple, DCF, or comparable transactions. Sensitivity to multiple and EBITDA assumptions is critical. Fulcrum analysis: map the capital structure waterfall against the estimated enterprise value. The tranche where cumulative claims exceed TEV is the fulcrum. Purchase price vs. recovery: cost basis in the fulcrum security vs. expected recovery (either in cash, new debt, or reorganized equity). Target: 30-50%+ upside from purchase to recovery. Plan economics: design the reorganized capital structure — how much debt, how much equity, who gets what. Ensure the reorganized company is sustainable (2-3x leverage). Exit analysis: how and when does the investor exit the equity? IPO, sale, secondary sale? What is the timeline to liquidity? Governance: post-emergence board composition, management incentives, shareholder agreement terms. Comparable LTO outcomes: study past loan-to-own situations in similar industries — what were the returns? What went wrong? Red flags: uncertain enterprise value (wide range of outcomes), contested restructuring (multiple competing plans), weak operating business (difficult to improve post-emergence), excessive post-emergence leverage.",
    capitalStructure: "The loan-to-own investor targets the fulcrum security — the point in the capital structure where value breaks. Above the fulcrum: claims are money-good (100% recovery) — too senior for the strategy. At the fulcrum: partial recovery — debt converts to equity at a ratio determined by recovery value and negotiation. Below the fulcrum: claims are out-of-the-money — recovery is minimal (warrants or nothing). Post-restructuring: the investor's position moves from debt (pre-petition) to equity (post-emergence). The reorganized capital structure is designed by the controlling creditor group. Typical outcome: senior claims → paid in full or receive new debt at par. Fulcrum claims → convert to reorganized common equity (50-100% ownership). Junior claims → receive warrants or are cancelled. Old equity → cancelled.",
  },

  claims: {
    category: "distressed", name: "Claims Trading", subtitle: "Unsecured claims markets in bankruptcy",
    color: T_.green, icon: "\uD83D\uDCE6",
    whatItIs: "Claims trading is the buying and selling of creditor claims against a bankrupt company. When a company files Chapter 11, all creditors have 'claims' — legal rights to payment. These claims can be transferred (sold) to new parties. A robust secondary market exists for trading claims — trade creditors sell their claims (at a discount) to distressed investors who believe the recovery will exceed the purchase price. Claims come in many forms: trade claims (owed to suppliers), rejection damages claims (from rejected contracts), litigation claims, tax claims, and general unsecured claims. The claims trading market provides liquidity to creditors who need cash now and investment opportunities for distressed specialists.",
    structure: "Claim types: secured claims (backed by collateral), priority claims (taxes, employee wages), general unsecured claims (trade payables, rejected contracts, litigation), subordinated claims, equity interests. Transfer mechanism: claims are transferred via assignment — the seller signs a transfer form, the buyer files it with the bankruptcy court, and the court processes the transfer. Claims agent: a court-appointed agent (Epiq, Kroll, Stretto) manages the claims register. Bar date: deadline for filing claims — claims filed after the bar date may be disallowed. Claims objection: the debtor or other parties can object to claims — disputed claims may be reduced or eliminated. Claim trading at price: typically quoted as cents on the dollar of the allowed claim amount. Example: a $10M trade claim trading at 40 cents costs $4M to acquire.",
    whoUses: "Sellers: trade creditors (suppliers, vendors) who are owed money and need liquidity — they'd rather receive 40-60 cents now than wait 12-24 months for an uncertain recovery. Landlords with rejection damage claims. Plaintiffs with litigation claims. Small creditors who can't afford to participate in the restructuring process. Buyers: distressed hedge funds (Elliott, Baupost, Mudrick, Contrarian Capital) buy claims at a discount, participate in the restructuring process, and seek to recover more than they paid. Claims accumulation can build a blocking position in a voting class. Claims brokers: specialized intermediaries (Capstone Capital, XRoads Solutions, Channel Capital) match buyers and sellers and facilitate claim transfers. Restructuring advisors: advise ad hoc creditor groups and help coordinate claims trading strategies.",
    risks: "Recovery uncertainty: the ultimate recovery on claims depends on the plan of reorganization, which may not be known for months or years. Recovery estimates can change dramatically as the case progresses. Claims disallowance: the debtor may object to claims — a $10M claim might be reduced to $3M after objection. The buyer inherits the risk of claim reduction. Preference risk: payments made to creditors in the 90 days before bankruptcy (1 year for insiders) can be 'clawed back' as preferential transfers — this reduces the claim and can create additional liability. Timeline risk: bankruptcy cases can last 6 months to 5+ years — capital is locked up with uncertain timeline. Subordination risk: claims can be subordinated (pushed down in priority) by the court for equitable reasons or under contract. Setoff risk: if the debtor has a counterclaim against the creditor, the claim may be offset — reducing recovery. Fraud/validity: claims may be inflated, duplicated, or fraudulent — due diligence on claim validity is essential.",
    howToAnalyze: "Allowed claim amount: verify the claim is properly filed, not subject to objection, and the amount is defensible. Review the proof of claim and supporting documentation. Recovery analysis: estimate the plan distribution for the claim class. For general unsecured claims: recovery = (enterprise value - senior claims) / total unsecured claims. Typically 10-50 cents for unsecured in Chapter 11. Purchase price vs. expected recovery: the 'spread' between cost and expected recovery is the investment return. A claim bought at 30 cents with expected 50-cent recovery = 67% gross return. Timing: how long until the plan is confirmed and distributions are made? Time value of money matters — 50 cents in 6 months is much better than 50 cents in 3 years. Claim class dynamics: is the claim in a class that can block the plan? Controlling a blocking position (1/3 in amount) gives negotiating leverage. Preference exposure: analyze payments received by the original creditor in the preference period — if there's preference exposure, the claim may be reduced. Legal review: review the proof of claim, any pending objections, setoff risks, and subordination arguments. Red flags: large preference exposure, pending objection, disputed amount, complex litigation claim, very small claim (not worth the transaction costs).",
    capitalStructure: "Claims priority in bankruptcy follows the Bankruptcy Code waterfall: (1) DIP / super-priority administrative claims, (2) Secured claims (to extent of collateral value), (3) Priority claims (wages, taxes), (4) General unsecured claims (trade, rejection damages, deficiency claims), (5) Subordinated claims (contractually or equitably subordinated), (6) Equity interests (almost always cancelled). Trade claims and most claims traded in the secondary market are general unsecured — they rank pari passu with other unsecured claims. Recovery depends entirely on how much enterprise value remains after satisfying all senior claims. In most Chapter 11 cases, unsecured creditors recover 10-50 cents; in some (asset-rich, low-leverage), they recover 70-100 cents.",
  },
};

const INSTRUMENT_ORDER = Object.keys(INSTRUMENTS);

export default function CreditInstruments({ initialTab }) {
  const [active, setActive] = useState(initialTab || INSTRUMENT_ORDER[0]);
  // eslint-disable-next-line react-hooks/set-state-in-effect -- syncs internal tab when sidebar changes initialTab on the same mounted instance
  useEffect(() => { if (initialTab) setActive(initialTab); }, [initialTab]);

  const inst = INSTRUMENTS[active];
  const activeCat = inst ? CATEGORIES.find(c => c.key === inst.category) : null;

  return (
    <div style={{ flex: 1, padding: "36px 52px", overflowY: "auto", fontFamily: FONT }}>
      {/* Category headers + tabs */}
      <div style={{ marginBottom: 24 }}>
        {CATEGORIES.map(cat => {
          const catInstruments = INSTRUMENT_ORDER.filter(k => INSTRUMENTS[k].category === cat.key);
          return (
            <div key={cat.key} style={{ marginBottom: 10 }}>
              <div style={{ fontSize: 10, color: cat.color, textTransform: "uppercase", fontWeight: 700, letterSpacing: "1px", padding: "6px 0 4px 4px" }}>{cat.label}</div>
              <TabBar
                tabs={catInstruments.map(key => ({ key, label: INSTRUMENTS[key].name }))}
                active={active}
                onChange={setActive}
                marginBottom={0}
              />
            </div>
          );
        })}
      </div>

      {/* Detail */}
      {inst && (
        <div>
          <div style={{ marginBottom: 24 }}>
            <div>
              <div style={{ fontSize: 24, fontWeight: 700, color: T_.text, letterSpacing: "-0.5px" }}>{inst.name}</div>
              <div style={{ fontSize: 14, color: T_.textDim, marginTop: 4 }}>{activeCat?.label}</div>
            </div>
            <div style={{ fontSize: 14, color: T_.textDim, marginTop: 8, lineHeight: 1.6, fontStyle: "italic" }}>{inst.subtitle}</div>
          </div>

          <Section title="What It Is" color={T_.blue}>
            <div style={{ fontSize: 13, color: T_.textMid, lineHeight: 1.7 }}>{inst.whatItIs}</div>
          </Section>

          <Section title="How It's Structured" subtitle="Mechanics, cash flows, key terms" color={T_.accent}>
            <div style={{ fontSize: 13, color: T_.textMid, lineHeight: 1.7 }}>{inst.structure}</div>
          </Section>

          <Section title="Who Uses It & Why" subtitle="Issuers, investors, hedgers" color={T_.green}>
            <div style={{ fontSize: 13, color: T_.textMid, lineHeight: 1.7 }}>{inst.whoUses}</div>
          </Section>

          <Section title="Key Risks" color={T_.red}>
            <div style={{ fontSize: 13, color: T_.textMid, lineHeight: 1.7 }}>{inst.risks}</div>
          </Section>

          <Section title="How to Analyze It" subtitle="Metrics, frameworks, red flags" color={T_.amber}>
            <div style={{ fontSize: 13, color: T_.textMid, lineHeight: 1.7 }}>{inst.howToAnalyze}</div>
          </Section>

          <Section title="Capital Structure Position" subtitle="Priority of claim, recovery expectations" color="#A855F7">
            <div style={{ fontSize: 13, color: T_.textMid, lineHeight: 1.7 }}>{inst.capitalStructure}</div>
          </Section>
        </div>
      )}
    </div>
  );
}
